INSERT INTO Brand (brand_name, brand_description, country_of_origin, logo_url, website_url)
VALUES
('Dolce & Gabbana', 'Dolce & Gabbana is an Italian luxury fashion brand founded in 1985 by Domenico Dolce and Stefano Gabbana. Known for its extravagant and elegant style, the brand incorporates colors and patterns inspired by Italian culture. Their collections feature a mix of classic Italian elegance and contemporary flair, drawing on Mediterranean themes with rich patterns, vibrant colors, and intricate details. Beyond fashion, Dolce & Gabbana has expanded into jewelry, watches, perfumes, and beauty products.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.dolcegabbana.com'),
('Roberto Cavalli', 'Roberto Cavalli is an Italian fashion house founded in Florence in 1970. The brand is celebrated for its glamorous and contemporary style, blending creativity with artisanal craftsmanship. The Roberto Cavalli Group has a diverse portfolio that includes Roberto Cavalli (ready-to-wear collections), Roberto Cavalli Junior, Just Cavalli, Roberto Cavalli Home, fragrances, and watches. Known for exotic prints, bold designs, and luxurious materials, Roberto Cavalli has made a mark on the luxury and fashion industry.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://robertocavalli.com'),
('Yves Saint Laurent', 'Yves Saint Laurent, also known as Saint Laurent and YSL, is a French luxury fashion house founded in 1961 by Yves Saint Laurent and his partner, Pierre Bergé. The brand is known for its innovative and groundbreaking designs, helping to shape fashion history. During the 1960s and 1970s, YSL popularized the beatnik look, safari jackets, tight pants, and thigh-high boots. In 1966, YSL debuted Le Smoking, a tuxedo suit for women. Cédric Charbit has been CEO of Yves Saint Laurent since 2024, and Anthony Vaccarello creative director since 2016.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ysl.com'),
('Mancera', 'Mancera is a perfume house founded in 2008 by Pierre Montale with the vision to combine Western elegance with Oriental grandeur. Mancera gathers exclusively the most beautiful materials both for the perfume and the packaging aesthetics - oud, rose water, saffron, leather, coffee, and vanilla. Elegantly designed bottles match the luxurious fragrances. Behind the Mancera brand, there is the wish to create the first brand that will enrich the West with the intensive and great ingredients of oriental perfumes. ', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Giorgio Armani', 'Giorgio Armani S.p.A., commonly known as Armani, is an Italian luxury fashion house founded in Milan by Giorgio Armani in 1975. The house designs, manufactures, distributes, and retails haute couture, ready-to-wear, leather goods, shoes, accessories, and home interiors. Armani is considered Italy''s third-biggest fashion group behind Gucci and Prada. The brand is built on class, quality, and exclusivity.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.armani.com'),
('Versace', 'Versace is an Italian luxury fashion company founded by Gianni Versace in 1978. The company produces upmarket Italian-made ready-to-wear and accessories, as well as haute couture pieces under the Atelier Versace brand. The Versace logo is the head of Medusa, a Greek mythological figure. Versace is known for its innovative designs having symbolic flashy prints and bright colors but with style.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.versace.com'),
('Xerjoff', 'Xerjoff is an artistic perfumery brand founded in 2007 in Turin by Sergio Momo. The brand blends the finest raw materials, a contemporary artistic sensibility, and Italian craftsmanship. Xerjoff perfumes are characterized by a rare mix of Italian style, tradition, and innovation. The brand''s mission is to develop and globally establish its brands: Xerjoff, Casamorati and Kemi.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://xerjoff.com'),
('Chopard', 'Chopard is a Swiss manufacturer and retailer of luxury watches, jewellery and accessories. Founded in 1860 by Louis-Ulysse Chopard, Chopard has been owned by the Scheufele family of Germany since 1963. Chopard is best known for making high-quality Swiss watches and jewellery, and its clients have included Tsar Nicholas II of Russia.', 'Switzerland', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.chopard.com'),
('Uniqo', 'UNIQLO is a clothing apparel company, which was originally founded in Yamaguchi, Japan in 1949 as a textiles manufacturer. Now it is a global brand with over 1000 stores around the world. UNIQLO is owned by Fast Retailing, based in Japan. UNIQLO''s clothing is aptly referred to as LifeWear. The brand philosophy “Made for All” positions its clothing to transcend age, gender, ethnicity and all other ways to define people.', 'Japan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.uniqlo.com'),
('Boucheron', 'Boucheron is a French luxury house producing jewelry, watches and amazing fragrances. The company is located in Paris. The House of Boucheron is a French family dynasty founded by Frederic Boucheron in 1858. Visionary designer and first of the great contemporary jewelers to open a boutique on Place Vendôme, Boucheron embodies excellence in Jewelry, High Jewelry and Watchmaking.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.boucheron.com'),
('Mont Blanc', 'Montblanc is a German manufacturer and distributor of luxury goods, founded in Berlin in 1906, and currently based in Hamburg. The company is most known for its luxury pens; it also designs and distributes bags, perfumes, small leather goods, and watches. Since 1993, Montblanc has been part of the Swiss Richemont group. Synonymous with excellence in craftsmanship and design, Montblanc has been pushing boundaries of innovation ever since it revolutionised the culture of writing in 1906. Montblanc unites time-honoured designs with European craftsmanship, bringing pieces to life across cities, including writing instruments in Hamburg, leather goods in Florence and timepieces in Switzerland.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://montblanc.com'),
('Parfums de Marly', 'Parfums de Marly is a French niche perfume house established in 2009 by Julien Sprecher. Its fragrances are inspired by the 18th Century French era and the splendor of the Royal court, particularly King Louis XV. The brand renews the splendor of the XVIIIth century, when the greatest perfumes were created for King Louis XV in commemoration of the prestigious horse races. The fragrances are bold, authentic, and respect French savoir-faire and the country''s cultural heritage.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.parfums-de-marly.com'),
('Juicy Couture', 'Juicy Couture is an American casualwear and dress clothing brand based in Arleta, Los Angeles, California. Best known for their velour tracksuits which became a luxury staple in the 2000s, the company was founded by Pamela Skaist-Levy and Gela Nash-Taylor in 1997 and was later purchased by the Liz Claiborne fashion company in 2003. Juicy Couture has turned into a global seller with their velour tracksuits and other fashions that span clothing, denim, handbags, shoes, intimates, swimwear, fragrance, accessories, sunglasses, yoga, petwear, and babywear. Juicy Couture is an LA lifestyle brand infused with casual glamor and an irreverent attitude, designed for girls all over the world.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://juicycouture.com'),
('Maqam', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('The Finest', 'Steven Smith Teamaker - Uncommonly delicious black teas, green teas, and herbal infusions; imported directly from friends and blended and packed in Portland, OR with artistry and care.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Al Majed For Oud', 'Al Majed For Oud Company was established in 1956 AD to establish a promising market in the field of oud trade through the wholesale sector by culminating in more than 60 years of experience in the manufacture of oud and perfumes. Their preparations across the Gulf market, by creating and innovating new aromatic lines have contributed to expanding their customer base and heading to the retail trade to reach more than 160 sales platforms in the Kingdom of Saudi Arabia and the Gulf countries. Al-Majed Aloes Oud Company is one of the most important pioneering companies in the perfume industry in the region.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Calvin Klein', 'Calvin Klein Inc is an American designer fashion retail chain marketing its eponymously branded products worldwide. Founded in New York in 1968, the brand''s minimalist and sensual aesthetic drives our approach to product design and communication, creating a canvas that offers the possibility of limitless self-expression. Calvin Klein specializes in mass-market ready-to-wear clothing for all genders and age groups as well as leather products, lifestyle accessories and shoes, home furnishings, perfume/cosmetics, eyewear, jewelry and watches in the mid-price segment.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://calvinklein.com'),
('Penhaligon''s', 'Penhaligon''s is a British perfumery established in 1870 by William Penhaligon. Originating as a barbershop, Penhaligon''s offered its first fragrance in 1872, Hammam Bouquet. The fragrance was inspired by the neighboring Turkish Bath and its sulfurous steam. Penhaligon''s perfumes are still made in England, using the rarest and most precious ingredients, from hand-pressed bergamot to jasmine at twice the cost of gold.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Very Important Notes', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Givenchy', 'Givenchy is a French luxury fashion and perfume house. It hosts the brand of haute couture and ready-to-wear clothing, accessories, perfumes and cosmetics of Parfums Givenchy. The house of Givenchy was founded in 1952 by designer Hubert de Givenchy. Givenchy is well-known for its haute couture clothing, perfumes, cosmetics, and accessories.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://givenchy.com'),
('Ajwa', 'Ajwa Perfume is an emerging perfume brand known for creative perfume creations and high-quality ingredients. The brand''s fragrances offer a wide range of olfactory experiences and appeal to people looking for unique and appealing scents. Ajwa Perfume has established itself in the perfume industry and is appreciated by perfume lovers.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Nicolai', 'Nicolaï is a niche perfume brand founded by Patricia de Nicolaï, a member of the prestigious Guerlain family & a highly respected perfumer in her own right. Nicolaï perfumes are exclusive creations and highly refined products. The quality and refinement of the raw materials used by Patricia de Nicolaï make every fragrance irresistibly sensual.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.pnicolai.com/'),
('Remal', 'Remal introduces exquisite options for Bakhoor influenced but its Arabian heritage. Designed by experts who have mastered the extraction of oriental notes, to add it in distinctive high-quality incense for a luxurious & warm home environment.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Candy Addict', 'Candy Addict is here to break the rules of perfume and bring you fresh, quirky, unforgettable scents that will keep heads turning all day long! Candy Addict was born out of a love for all things fragrance. We use these fabulous fragrances to bring you an incredible range of hair & body mists, perfumes, home fragrances & a wonderful bath & body selections!', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Al Mas', 'Al Mas is a Saudi Arabian perfume brand that was created in 2012. It is involved in the manufacturing and trading of perfumes and roll-on perfumes. The brand offers you an aromatic collection of scents. The products are blended by superb fragrance collections that rediscover organic forms inspired by nature. If you are searching for a long time fragrance, Al Mas is the perfect option for you.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Orto Parisi', 'Orto Parisi, founded in 2014 by perfumer Alessandro Gualtieri, is an Italian niche fragrance brand renowned for bold, earthy, and unisex scents inspired by Gualtieri''s childhood experiences in his grandfather''s garden in Puglia, Italy. The brand emphasizes capturing natural, raw, and animalistic aromas often overlooked or suppressed in contemporary perfumery, aiming to evoke profound emotions and vivid memories through each fragrance.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Gucci', 'The House of Gucci was founded by Guccio Gucci in 1921. Inspired by the beautiful luggage he had seen travelers carrying while working at the Savoy Hotel in London, Gucci returned to Florence with a goal of combining the refined elegance of the wealthy travelers he observed with the fine craftmanship of traditional Florentine artisans. The company''s equestrian-themed quality leather goods were in high demand, and when leather was scarce during World War II, Gucci''s innovative use of hemp, linen and jute expanded the brand''s aesthetic.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.gucci.com/'),
('Burberry', 'Burberry is a luxury British design house founded by Thomas Burberry in 1856. This house distinguished itself with fashion and accessories, including a now-iconic trench coat and the brand''s unique and recognizable tartan pattern which has become one of the most-copied motifs in fashion. Burberry was granted a Royal Warrant for Clothing from the British Royal Family. In addition to their fashion line and accessories, the Burberry brand offers an exclusive line of fragrances for men and women—many in bottles adorned with the company''s signature tartan—under arrangement with Inter Parfums.', 'British', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.burberry.com/'),
('Lorenzo Villoresi Firenze', 'Lorenzo Villoresi Firenze is a brand born from the creations of Lorenzo Villoresi, an Italian alchemist of fragrances known throughout Italy and beyond. His perfumes are born from an artistic feeling that is the heart of this perfume house, each fragrance in its own way is a magical mix of aromatic substances that meet, arousing emotions and feelings.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.lorenzovilloresi.it'),
('Exclusive Bundles', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Dkhoun', 'Dkhoun is a leading company specialized in perfumes and fresheners, targeting customers with high-end tastes. It is managed by a group of companies producing sophisticated perfumes, aromatic oils and vapors.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Guerlain', 'Guerlain is a French perfume, cosmetics, and skincare house, among the oldest in the world. Founded in 1828 in Paris by Pierre-François Pascal Guerlain, the house was family-run until 1994 when it was bought by LVMH. Guerlain is known for fragrances like Jicky, Shalimar and La Petite Robe Noire.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Lacoste', 'Lacoste is a French designer sports fashion company founded in 1933 by tennis player René Lacoste and André Gillier. It is known for its green Crocodile logo and sells clothing, footwear, sportswear, eyewear, leather goods, perfume, towels, and watches. The brand draws inspiration from sporting values.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.lacoste.com/'),
('Deem Perfumes', 'Deem Perfumes is an Emirati perfume brand founded in October 2020. They provide long-lasting scents at competitive prices, blending Arabic and French fragrances. Known for luxurious and special perfumes reflecting experience and quality. They offer a range of unisex perfumes formulated with high-quality ingredients suitable for regular and special occasions.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Jaguar', 'Jaguar Fragrances symbolizes the Jaguar attributes of style, performance and modernity. The perfumes draw on the DNA of the Jaguar aesthetic and its iconic heritage. They are a constant source of surprise and inspiration, combining powerful character and proud dynamism.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Narciso Rodriguez', 'Narciso Rodriguez is a luxury fashion and fragrance brand known for its minimalist and elegant approach to design. Its fragrances are sensual, modern, and timeless, often featuring musky and woody notes. Founded by the American fashion designer Narciso Rodriguez in 1997.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Chanel', 'Chanel is a French luxury fashion house founded in 1910 by Coco Chanel in Paris. It specializes in women''s ready-to-wear, luxury goods, and accessories. The brand is known for its No. 5 perfume and "Chanel Suit".', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Elie Saab', 'Elie Saab is a Lebanon-based fashion designer who started his business in the early 1980s. The ELIE SAAB house has been established as one of the major leaders in the HAUTE COUTURE category globally. Elie Saab has continued to build on the inherent savoir-faire and innate elegance for which it is renowned, expanding into the Ready-to-Wear, Bridal, Accessories, Eyewear & Fragrance categories.', 'Lebanon', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.eliesaab.com/'),
('Rekaz', 'Rekaz is a majestic Arabian brand, that delivers both luxury & eastern elegance in one set of Eau De Parfum and Perfume Oil. Each bundle from Rekaz provides a unique aromatic note, with the highest quality possible. Modern, elegant & sophisticated these are the characters that will make you fall in love with Rekaz, one of a kind collection.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://rekaz.io'),
('Tom Ford', 'Tom Ford is an American luxury fashion house founded by designer Tom Ford in 2005. Its product line features ready-to-wear and made-to-measure offerings, as well as footwear, accessories, handbags, cosmetics and fragrances. Known for modern glamour and unparalleled style through impeccable tailoring and craftsmanship.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Rasasi', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Nasomatto', 'Nasomatto, founded in 2007 by Alessandro Gualtieri, is a fragrance brand known for its intense, provocative, and unusual scents. Gualtieri''s creations aim to evoke deep feelings and desires, using high-quality ingredients and high concentrations of essential oils. The brand maintains a sense of mystery, offering strange, evocative descriptions rather than fragrance notes.', 'Netherlands', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.nasomatto.com/'),
('Esteban', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Bvlgari', 'Bvlgari, stylized as BVLGARI, is an Italian luxury fashion house founded in Rome in 1884 by Sotirios Voulgaris. The brand is known for its jewelry, watches, fragrances, accessories, and leather goods. Bvlgari''s style features vibrant color combinations, balanced volumes, and Roman motifs. The trademark BVLGARI is derived from the founder''s surname.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.bulgari.com/'),
('Coach', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Bentley', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Van Cleef & Arpels', 'Van Cleef & Arpels is a French luxury jewelry company founded in Paris in 1906 by Alfred Van Cleef and his father-in-law Salomon Arpels. Their jewelry often features flowers, animals, and fairies. The Maison is known for its creativity, timeless pieces, and craftsmanship, using gemstones and materials. The Alhambra collection, inspired by the four-leaf clover, is one of their iconic designs.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.vancleefarpels.com'),
('Lancome', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Lalique', 'Lalique is a French luxury glassmaker, founded by René Lalique in 1888. The company is known for producing glass art, including perfume bottles, vases, and hood ornaments. Today, Lalique produces luxury products in five categories: jewellery, decorative items, interior design, perfumes, and art.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.lalique.com'),
('Alexandre.J', 'Alexandre J is a French designer who launched his perfume brand in 2012. He aims to create beauty through luxurious packaging and exceptional fragrances, drawing inspiration from different cultures. His perfumes feature unusual fragrant notes, and the bottles are designed as works of art.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.alexandrejparfums.com/en/'),
('Al Dakheel Oud', 'Al Dakheel Oud is a Saudi company founded in 1983, specializing in the manufacture, production, and trade of oud and perfumes. The company has over 100 branches across Saudi Arabia and offers over 500 products. It holds ISO 9001:2015 and ISO 14001 certificates and is licensed by the Saudi Food & Drugs Authority. They are known for quality products and Good Manufacturing Practices (GMP).', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.aldakheeloud.com'),
('Dr. Vranjes Firenze', 'Dr. Vranjes Firenze is an Italian luxury home fragrance brand founded in 1983 by Dr. Paolo Vranjes in Florence, Italy. The brand is known for high-quality handcrafted fragrances inspired by Florentine artisanship and fragrance science. Their products include home diffusers, scented candles, and personal fragrances and has a presence in over 75 countries.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://drvranjes.com'),
('Chloe', 'Chloé is a French luxury fashion house founded in 1952 by Gaby Aghion. The brand is known for its romantic, feminine designs, using soft colors and flowing fabrics. They offer luxury prêt-à-porter, handbags, shoes, and fragrances. Chloé is owned by Richemont Group.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://chloe.com'),
('Sedr Alkhaleej', 'Sedr Alkhaleej is a Saudi brand excelling in the perfumery industry with an authentic Arab character. They produce a mixture of eastern and western perfumes, incense, air fresheners and body sprays. Sedr Alkhaleej uses special perfumes formulation & oriental notes like musk, Oud and Amber.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Hugo Boss', 'Hugo Boss AG is a German designer fashion company headquartered in Metzingen, Baden-Württemberg. Founded in 1924 by Hugo Ferdinand Boss, the company sells clothing, accessories, footwear, and leather goods. They operate under the brands BOSS and HUGO, and also license products for children''s fashion, eyewear, watches, home textiles, and fragrances.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://group.hugoboss.com/'),
('Armand Basi', 'Armand Basi is a Spanish fashion and lifestyle brand founded by Mercedes Basi in the 1940s in Barcelona, Spain. The brand offers ladies'' and men''s wear, shoes, bags, accessories, watches, sunglasses, belts, homewear and fragrances. The brand aims at middle and upper middle class young professionals of both sexes in the age group of 25-35.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://armandbasi.com'),
('Byredo', 'Byredo is a Swedish company founded in Stockholm in 2006 by Ben Gorham. The brand produces luxury fragrances, leather goods, and accessories. Byredo focuses on quality and translating memories and emotions into tangible products and experiences. The name Byredo is a portmanteau of "by redolence".', 'Sweden', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.byredo.com/uk_en/'),
('Swiss Arabian', 'Swiss Arabian Perfumes Group was established in 1974 in UAE. The Group owns several perfume brands, including Swiss Arabian, a luxury perfume division. Swiss Arabian Perfumes is the first perfume manufacturer in the United Arab Emirates. Their exquisite range of perfumes offers The Perfect Mix of the East and the West.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://swissarabianperfumes.com'),
('Dunhill', 'Alfred Dunhill Limited is a British luxury goods brand, specializing in ready-to-wear, custom and bespoke menswear, leather goods, and accessories. The company is headquartered in Westminster, London. Synonymous with British craftsmanship and design, dunhill is the foremost British men''s luxury House for today.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://dunhill.com'),
('S.T. Dupont', 'S.T. Dupont is a French manufacturing company based in Paris, which has been making luxury goods since its founding in 1872. Products commercialized include handbags, lighters, collectible pens, perfumes cigarettes and recently other gadgets using the trademark diamond-head pattern. It is a wholly owned subsidiary of Hong Kong luxury goods company Dickson Concepts.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://st-dupont.com'),
('Woud', 'Woud is a Danish design brand founded in 2014 by Mia and Torben Koed. The brand manufactures furniture, lighting, and home accessories characterized by high quality, innovativeness, and simple, pleasing design rooted in Scandinavian traditions. Woud aims to create long-lasting, purposeful designs in collaboration with emerging talents and renowned designers.', 'Denmark', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://woud.dk/'),
('Memo Paris', 'Memo Paris is a prestigious Parisian perfume house founded in 2007 by Clara Molloy and her husband John Molloy. The brand''s philosophy centers on reinterpreting perfume through journeys, drawing inspiration from magical destinations worldwide and high-quality natural ingredients. Each fragrance aims to evoke memories and feelings associated with different corners of the world, transporting you to distant places through enchanting fragrance notes. The brand builds its identity around magical destinations and intense raw materials.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.memoparis.com'),
('Dior', 'Christian Dior SE, commonly known as Dior, is a French multinational luxury goods company controlled by Bernard Arnault. Founded by Christian Dior in 1946, the House of Dior is known for its haute couture, ready-to-wear, fashion accessories, perfumes, cosmetics, and more. Dior revolutionized the perfume industry with the launch of Miss Dior and is synonymous with elegance, craftsmanship, and innovation. The company has a business presence across Asia-Pacific, Europe, the Middle East and Africa and the Americas regions.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.dior.com'),
('Parfums GrÃƒÂ¨s', 'Founded in 1941, the Grès fashion house has been an uncompromising leader in haute couture for several decades. Grès entered the perfume world in 1959. Over the years, the company has built a rich heritage and achieved genuine legitimacy in perfumery. Parfums Grès targets confident, chic women with a feel for vintage style.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Houbigant', 'Houbigant Parfum is a perfume manufacturer founded in Paris, France, in 1775 by Jean-François Houbigant. The brand originally sold gloves, perfumes, and bridal bouquets. Several European rulers including Napoleon, Napoleon III, Alexander III of Russia, and Queen Victoria used Houbigant''s perfume. Houbigant was the first perfume house to discover how to isolate particular molecules from natural raw materials—specifically coumarin, which is isolated from the tonka bean. In 1912, they introduced Quelques Fleurs, the first multi-floral bouquet.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://houbigant-parfum.com/'),
('Mariah Carey', 'Mariah Carey is an American singer, songwriter, record producer, and actress. She is also the founder of an Irish cream brand called Black Irish, which launched in August 2021. Carey has also launched Mariah''s Cookies, an online dessert brand, in partnership with Virtual Dining Concepts.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mariahcarey.com'),
('Alwaleef', 'Alwaleef is a leading perfume brand and one of the brands of Tiamen company, offering you a distinctive, unique and modern fragrance package to enrich your day. Alwaleef is known for romantic, soft oriental fragrances. Through more than 175 aromatic products and 90 points of sale spread in Saudi Arabia, UAE and Bahrain.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://alwaleef.com'),
('Escada', 'ESCADA is a luxury women''s designer clothing company headquartered in Aschheim, Germany. Founded in 1978 by Margaretha and Wolfgang Ley, the brand represents effortless elegance, feminine strength and the modern women of today. ESCADA is known for its love of bold color, print, and detail. The brand offers womenswear, shoes, and accessories for everyday, business, and leisure wear, as well as glamorous evening attire. Perfumes, eyewear, watches, and jewellery are also sold under licence in the ESCADA name.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.escada.com'),
('Fendi', 'Fendi is an Italian luxury fashion house producing fur, ready-to-wear, leather goods, shoes, fragrances, eyewear, timepieces and accessories. Founded in Rome in 1925 by fashion designers Edoardo Fendi and Adele Casagrande, Fendi is known for its fur, fur accessories, and leather goods. Since 2001, Fendi has been part of the "Fashion & Leather Goods" division of the French group LVMH. Its headquarters are in Rome, in the Palazzo della Civiltà Italiana.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.fendi.com'),
('Initio', 'INITIO Parfums Privés, founded in 2015, is a French niche brand that enhances scents to a whole new level,  aiming to influence mood, behavior, and self-perception through sophisticated olfactory experiences. The brand bases its concept on scientific findings that scents exert a power on our psyche and directly influence human behavior through our emotions.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.initioparfums.com'),
('Hermes', 'Hermès International S.A. is a French luxury fashion house established in 1837. Specializing in leather goods, silk goods, lifestyle accessories, home furnishings, perfumery, jewelry, watches and ready-to-wear, since the 1950s, its logo has been a depiction of a ducal horse-drawn carriage. The brand is known for its equestrian accessories, Kelly and Birkin bags, and elegant silk scarves.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.hermes.com'),
('Franck Olivier', 'Franck Olivier is a fragrance brand established in 1993 and known for its elegant and distinctive creations in the world of perfumery, offering a wide range of fragrances for men and women, from fresh and subtle scents to more intense and seductive fragrances. Located in the heart of Paris, the brand is inspired by the artistic and cultural atmosphere of this emblematic city.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Tous Les Jours', 'Tous les Jours is a South Korean bakery franchise owned by CJ Foodville, established in 1996. Tous les Jours means ''every day'' in French. It is a French-Asian-inspired bakery serving a selection of baked goods and beverages made with high-quality ingredients. As of 2021, it has more than 1,650 locations worldwide.', 'South Korea', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.tlj.co.kr/'),
('Davidoff', 'Davidoff is a Swiss premium brand of cigars, cigarettes, and smoker''s accessories. The Davidoff cigarette brand is owned by Imperial Brands, while the non-cigarette portion is owned by Oettinger Davidoff AG, based in Basel, Switzerland. The brand originates from Zino Davidoff, who ran a tobacco specialist shop in Geneva and was known as the ''King of Cigars''.', 'Switzerland', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.davidoff.com'),
('Caron', 'Caron has been devoted to providing high quality temperature and environmental control equipment since 1985. Caron has been a leader in high quality, affordable yarns for knitters and crocheters for over 100 years. Based in North Carolina, Caron''s story starts all the way back in the 1897 when the family owned textile mill began producing yarns for home crafting.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://caronproducts.com/'),
('Thierry Mugler', 'Thierry Mugler is a French fashion designer and photographer known for his 1980s power fashions and credited with introducing a new fragrance trend or category—gourmand—in the 1990s. His style is distinguished by its futuristic shapes and fantasy elements.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Valentino', 'Valentino S.p.A. is an Italian luxury fashion house founded in 1960 by Valentino Garavani. A symbol of crafting excellence, creativity and uniqueness, Valentino continues to inspire individuality by redefining the values of mastery and emotional beauty. The company has its registered office in Milan, while the creative direction and the Valentino Foundation is based in Rome.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.valentino.com'),
('Anfasic Dokhoon', 'Anfasic Dokhoon is a luxury perfume brand based in the United Arab Emirates, specializing in Arabian fragrances. The brand is known for its unique blends and traditional scents, incorporating oud and other premium ingredients. Anfasic Dokhoon reflects a modern pursuit of luxury, elegance, and quality, capturing the spirit of a contemporary Arab world that embraces sophistication without losing its rich cultural roots.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mhgboutique.com/collections/anfasic-dokhoon'),
('Atelier Cologne', 'Atelier Cologne is a luxury fragrance brand founded in Paris in 2009 by Sylvie Ganter and Christophe Cervasel. Known for its unique ''cologne absolue'' concept, the brand combines the freshness of traditional cologne with the intensity of perfume. Atelier Cologne offers a collection of high-quality, long-lasting fragrances inspired by memories and travel, emphasising the use of natural ingredients.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ateliercologne.com'),
('Jennifer Lopez', 'Jennifer Lopez is an American actress, dancer, TV personality, fashion designer, and platinum-selling recording artist. Always known for her beauty, fashion sense, and glamorous looks, Lopez launched her first fragrance, Glow, in 2002. The curvy bottle shape of Glow was designed to resemble the actress''s famous figure.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mabkharat Alemarat', 'For more than 13 years, Mabkharat Alemarat Company has been specializing in selling incense products, fragrances, and oriental accessories in Saudi Arabia. The company is affiliated to Tayamun, which has achieved great success in manufacturing and marketing high-quality perfumes and incense. It has a wide customer base across the Kingdom and Gulf countries, with more than 300 sales points.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Viktor & Rolf', 'Viktor&Rolf is an avant-garde luxury fashion house founded in 1993 by fashion artists Viktor Horsting and Rolf Snoeren. Widely recognized and respected for its provocative Haute Couture and conceptual glamour, Viktor&Rolf aspires to create spectacular beauty and unexpected elegance through an unconventional approach to fashion. Their luxury products include exclusive eyewear line Viktor&Rolf Vision, and an addictive catalogue of fragrances featuring worldwide bestsellers: Flowerbomb, Spicebomb and Good Fortune.', 'Netherlands', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.viktor-rolf.com'),
('Montale', 'Montale is a niche perfume brand founded in 2003 in Paris by Pierre Montale, who translated his passion for Middle Eastern fragrances into olfactory compositions that give special prominence to oud, spices, amber, rose and sandalwood. Its connection with the Middle East is manifested not only in the use of ingredients from that region, but also in a high concentration of exquisite essential oils, which gives its perfumes a great quality, projection and duration.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Nikos', 'Nikos is a line of perfumes that belongs to Coty Inc. company. It owns three fragrances, Nikos Sculpture Morning Feel, Nikos Sculpture Blue Breeze and Nikos Sculpture Homme, and also other cosmetics for men such as aftershave Sculpture. Nikos is known for a wide variety of perfumes, with unmistakable fragrances for Nikos lovers.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Tiziana Terenzi', 'Tiziana Terenzi is an Italian family perfume house that has become one of the most exclusive niche perfume brands all over the world. The Italian family perfume house Tiziana Terenzi has become one of the most exclusive niche perfume brands all over the world. It won the hearts of its customers with an interesting history, skills, knowledge, and passion for creating unique and luxurious products. Inspired by art and living in a moment, Tiziana and Paolo Terenzi created perfumes of unique fragrance, seductively scented candles, room fresheners, and home decoration made of the finest porcelain.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Cartier', 'Cartier International SNC, or simply Cartier, is a French luxury-goods conglomerate that designs, manufactures, distributes, and sells jewelry, watches, leather goods, sunglasses and eyeglasses. Founded by Louis-François Cartier in Paris in 1847, the company remained under family control until 1964. The company is headquartered in Paris, France, and is currently a subsidiary of the Swiss Richemont Group.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.cartier.com'),
('Lanvin', 'Lanvin is a French luxury fashion house founded in 1889 by Jeanne Lanvin in Paris. It is the oldest French fashion house still in operation. From its humble beginnings as a millinery, the brand has grown into a global fashion empire. With its unique design concept, exquisite craftsmanship and excellent quality, Lanvin has won the favor of fashion lovers around the world. It is now a subsidiary of Shanghai-based Lanvin Group.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Giorgio Beverly Hills', 'Giorgio Beverly Hills is an American brand founded by Fred and Gayle Hayman in 1961. Named after the luxury boutique, the fragrance of the same name would go on to become one of the most iconic fragrances of the 1980s. Located at the corner of Rodeo Drive and Dayton way, Giorgio Beverly Hills offered a large selection of designer clothes, many of which were exclusive to the boutique. The shop was known for its club-like atmosphere and unusual decor, and it also featured a reading room, a billiards room and a full oak bar.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Azzaro', 'The Azzaro brand was created in the image of its founder, Loris Azzaro. A Tunisian-born Sicilian who embodied the essence of Mediterranean luxury—tanned, sensual, hedonistic—the designer quickly established a reputation in the late 1960s with his glamorous and sexy fashions. The brand expanded its offering to include fragrances, introducing Azzaro for Women in 1975, to be followed soon by the modern classic Azzaro pour Homme in 1978. ', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Elizabeth Arden', 'Elizabeth Arden, established by Florence Nightingale Graham in 1910, revolutionized the beauty industry with her visionary approach to skincare and cosmetics. Recognized for iconic products like the Eight Hour Cream and Ceramide Capsules, Elizabeth Arden epitomizes timeless elegance and innovation. With a commitment to empowering women and delivering luxurious, high-quality products, the brand continues to be a leader in skincare, makeup, and fragrance.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.elizabetharden.co.uk'),
('Tommy Hilfiger', 'Tommy Hilfiger B.V., formerly known as Tommy Hilfiger Corporation and Tommy Hilfiger Inc., is an American clothing brand that manufactures apparel and licensed products such as footwear, accessories, fragrances and home furnishings. The company was founded in 1985 by Tommy Hilfiger. Tommy Hilfiger designs are based on classic American shapes for the ultimate wardrobe must-haves, with music also as a major influence. As of 2022, global sales in retail through the brand were US$9.1 billion.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://global.tommy.com'),
('Stella McCartney', 'Stella McCartney is the namesake high fashion label of British designer Stella McCartney. Her collections include ready-to-wear for women and men, accessories, lingerie, eyewear, perfumes and kidswear. The designer is a committed vegetarian and firm supporter of animal rights, and is known for use of environmentally-friendly and animal-free alternatives in her collections. She launched her eponymous fashion house in a partnership with Kering as a 50/50 joint venture, showing her first collection in 2001. In 2019, she entered a partnership with LVMH Moët Hennessy–Louis Vuitton, while retaining a majority stake in her brand.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.stellamccartney.com'),
('Minis', 'Mini (stylised as MINI) is a British automotive brand founded in Oxford in 1969, marketed by German multinational automotive company BMW since 2000, and used by them for a range of small cars assembled in the United Kingdom, Austria, Netherlands (until 16 February 2024) and Germany. The current Mini range includes the Cooper Hardtop/Hatch/Convertible (three and five-door hatchback), Aceman and Countryman (five-door crossovers). BMW acquired the brand in 1994 when it bought Rover Group (formerly British Leyland), which owned Mini, among other brands.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://mini.com'),
('Kun Safi', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('COZY', 'AMISU''s brand-new collections embrace fashion that perfectly complements your unique style. This season brings a fresh breeze, offering a wide range of looks for every occasion.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Abreez', NULL, 'Pakistan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('WAW', 'WAW LOGOS provides custom made logos design services well suited for their client''s brands, companies, products, apps, websites, hotels, restaurants or any other business. They design meaningful relevant sketch-based logo design & brand identity solutions.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Guess', 'Guess Inc. is an American clothing company, notable for its black-and-white advertisements. Guess licenses its brand on other fashion accessories, such as watches, jewelry, perfumes, bags and shoes. Guess was established in 1981 by the Marciano brothers, inspired by a European influence, the Marcianos redefined denim. GUESS quickly became a symbol of a young, sexy and adventurous lifestyle.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.guess.com'),
('Vintage', 'Vintage Brand is honored to celebrate our rich American sporting culture by offering the world''s largest collection of unique vintage sports apparel and gear. All of our products are printed and designed in the U.S.A, and created from over 20,000 historic tickets, programs, decals, scorecards, game schedules, and other classic sports images. Vintage Brand was founded in 2017 by a small group of sports minded enthusiasts with a vision to relive sports history.', 'Copenhagen', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAJUIVoMkvgVXbd0B8X4pCWq8l_C3519mNiqV7fgyUifKSs1bJRnfLHTOL3KxmLC9XUvDXp1-27LFUpSzoYQKD73D5hRrC7bauIX9XqEc_3swEvVR9Q='),
('Perfume Co.', 'Perfume Co. is a new fragrance brand. The earliest edition was created in 2021 and the newest is from 2023.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('One Word', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('The Different Company', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('John B. Sensual', 'Sensual by Johan B is a Floral Fruity fragrance for women. Top notes are Bergamot, Tangerine, Black Currant, Nectarine and Apple; middle notes are Gardenia, Magnolia, Jasmine, Freesia and Lily-of-the-Valley; base notes are Patchouli, Musk, Sandalwood, Vanilla and Amber. It is manufactured by Geparlys, a French perfume company.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mugler', 'Mugler, originally known as Thierry Mugler, is a French fashion designer and photographer known for his 1980s power fashions and is widely credited with introducing a new fragrance trend or category—gourmand—in the 1990s. Mugler''s style is distinguished by its futuristic shapes and fantasy elements. Mugler opened his first Paris boutique and also launched a menswear collection in 1978. Mugler''s first fragrance, Angel, was introduced in 1992.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mugler.com/'),
('Rochas', 'Rochas is a French brand that began as a fashion house founded by Marcel Rochas in 1925. From 1925 until 1953, Marcel Rochas dressed women in forward-thinking fashions that also celebrated traditional feminine silhouettes. The company expanded its offerings to include fragrances, starting with a trio of perfumes, Avenue Matignon, Air Jeune and Audace, in 1934. The perfumes were taken off the market during World War II, but the company''s most famous fragrance, the classic Femme, was launched in 1943 and remains a perennial best-seller. ', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.rochas.com/'),
('Cerruti', 'Cerruti 1881, also known as Cerruti, is an Italian luxury fashion house founded in 1967 and headquartered in Paris. It was founded by the Italian stylist and fashion producer Nino Cerruti. It was named "1881" because Nino''s grandfather established the family woolen mill, Fratelli Cerruti Wool Mill, in Italy in 1881.The Cerruti house designs, manufactures, distributes, and retails luxury ready-to-wear, jeans, fragrances, sportswear, leather goods, watches, and accessories.', 'Italy/France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.cerruti.com/'),
('Cacharel', 'Cacharel is a French brand offering fashions, accessories and fragrances. Founded in 1962 by designer Jean Bousquet, the company takes its name from the local term for Anas querquedula, a small duck native to the Camargue region of France. Cacharel gained notoriety after one of its modern pink shirts appeared on the cover of Elle in 1963, and the company''s reputation expanded throughout the 1970s. Noted for its youthful, feminine fashions, the house of Cacharel extended its image with the launch of its first scent, Anaïs Anaïs, in 1978.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.cacharel.fr'),
('Clinique', 'Clinique Laboratories, LLC is an American manufacturer of skincare, cosmetics, toiletries and fragrances, usually sold in high-end department stores. It is a subsidiary of the Estée Lauder Companies. In 1968, a savvy beauty editor asked a leading dermatologist “Can great skin be created?” Clinique was born. Clinique''s mission has always been to provide the safest, most effective formulas in simple routines that bring remarkable results.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.clinique.com'),
('Aigner', 'Etienne Aigner AG is a luxury accessories house based in Munich, Germany. Founded by Etienne Aigner in 1949, the brand is known around the world for its quality and craftsmanship in bags, wallets and accessories, and for its signature dark red leather that echoes the color of fine chianti. The brand’s logo—a letter "A" stylized as a horseshoe—reflects the ongoing influence of equestrian themes in the collection.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.aignermunich.com'),
('Trussardi', 'Trussardi is an Italian fashion and lifestyle brand that celebrated 100 years in business in 2011. Founded originally as a glove factory by Dante Trussardi in 1911. Trussardi is an Italian fashion house based in Milan, Italy, and specialized in leather goods, ready-to-wear, perfumes, and accessories. The iconic greyhound is the undisputed symbol of Trussardi, distinguished by its elegant and contemporary style.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.trussardi.com'),
('Carolina Herrera', 'Over the last four decades, Venezuelan-born Carolina Herrera has become one of the world''s most distinguished designers, garnering numerous accolades and high-profile fans for her signature sophistication and quintessential American elegance. Known for her personal style, she founded her namesake brand in 1980. Herrera has dressed various First Ladies of the United States, including Jacqueline Onassis, Laura Bush, Michelle Obama, and Melania Trump.', 'Venezuela', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.carolinaherrera.com'),
('La Perla', 'La Perla is a London-headquartered Italian lingerie and swimwear maker owned by entrepreneur Lars Windhorst through Tennor Holding B.V. The brand was founded by couturière Ada Masotti in Bologna in 1954. The Operating La Perla Group is a leading designer, manufacturer and seller of high-end luxury lingerie, nightwear and beachwear, as well as ready-to-wear products and accessories. It trades under the brand “La Perla” and the product portfolio reflects La Perla''s exclusivity and uniqueness, by combining creativity, innovation and style with quality and craftsmanship.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.laperla.com'),
('Jean Paul Gaultier', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Ajmal', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Atelier Des Ors', 'Atelier Des Ors is an Artistic Fragrance House inspired by the magnificence of Haute Parfumerie. Born of the desire to create sophisticated, alluring and sensual scents, Atelier Des Ors crafts stories on skin, evoking strong emotions and poetic journeys. Craftsmanship, the art of perfumery and gold are fundamental to the Atelier Des Ors DNA. Founded in France in 2015, Atelier Des Ors is now based in Grasse in the Villa Primerose.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://atelierdesors.com/en/'),
('Kholasaat', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Thameen Fragrance', 'Thameen London is an English niche fragrance brand, uniquely combining eastern opulence and western refinement. Thameen means precious and our finest fragrances are inspired by the world''s most precious jewels and the enchanting stories behind them. All fragrances are created with a profound love and passion for the craftsmanship of fine niche perfumery with world renowned perfumers.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.thameenfragrance.com'),
('Ibraheem Al.Qurashi', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Prada', 'Prada is an Italian luxury fashion house founded in 1913 in Milan by Mario Prada. It specializes in leather handbags, travel accessories, shoes, ready-to-wear, and other fashion accessories.  Since 1913, Prada has been synonymous with cutting-edge style. Its intellectual universe combines concept, structure and image through codes that go beyond trends.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.prada.com'),
('Paco Rabanne', 'Francisco Rabaneda Cuervo (18 February 1934 – 3 February 2023), more commonly known under the pseudonym of Paco Rabanne was a Spanish-born naturalised-French fashion designer. Rabanne rose to prominence as an enfant terrible of the fashion world in the 1960s with his use of unconventional materials such as metal and plastic in his clothing, and for his incorporation of futuristic elements in his designs, gaining notoriety for his space-age style.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.pacorabanne.com'),
('IL Profvmo', 'Il Profvmo is an Italian niche perfume house founded by cosmetologist/aromatherapist Silvana Casoli. The house offers several lines of fragrances: the Classic line; the Osmo line, which are designed with a slow evaporation rate and become a personal fragrance as they fade; the Soliflor line, which celebrates the splendor and magnificence of nature through individual floral scents; and Multiflor line, which offers olfactory bouquets. Il Profvmo also offers home fragrances and candles.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ilprofvmo.com'),
('Emanuel Ungaro', 'Emanuel Ungaro was an Italian-French fashion designer who founded his eponymous fashion house in 1965. Known for bright colors and bold combinations, Ungaro''s designs were influenced by his fascination with feminine beauty. The brand produces haute couture, ready-to-wear, and licensed products.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ungaro.com'),
('Rihanna', 'Robyn Rihanna Fenty is a Barbadian singer, businesswoman, and actress. She is the best-selling female recording artist of the 21st century. Aside from music, Rihanna is recognized for her humanitarian involvement, entrepreneurship, and fashion industry influence. She established the Clara Lionel Foundation, cosmetics brand Fenty Beauty, and fashion house Fenty under LVMH, becoming the first black woman to lead a luxury brand for LVMH.', 'Barbados', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://rihanna.com'),
('Selena Gomez', 'Selena Marie Gomez is an American actress, singer, songwriter, producer, and businesswoman. Gomez began her career as a child actress and emerged as a teen idol. She is also known for founding the cosmetic company Rare Beauty in 2020, valued at $2 billion in 2024, and non-profit Rare Impact Fund. She has appeared in listicles such as the Time 100 (2020) and Forbes 30 Under 30 (2016 and 2020), was named Billboard''s Woman of the Year (2017), and was made a member of the Order of Arts and Letters by the Government of France (2024). She is the most-followed woman on Instagram, and among the wealthiest musicians.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://selenagomez.com'),
('Vince Camuto', 'Named for our legendary founder, Vince Camuto creates beautiful shoes that deftly mix fashion and function. Elegantly designed, meticulously crafted and precisely constructed for fit, our footwear delivers on Vince''s principles of style, comfort and accessible pricing. Vince''s Italian roots, his craftsman''s eye and his passion for stylish living lie at the heart of our brand. We remain committed to his values.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.vincecamuto.com'),
('Jean-Louis Scherrer', 'Jean-Louis Scherrer was a Parisian fashion designer and couturier. Although he had name recognition and was known for his work, he is mainly noted for being the first couture designer to be sacked from their own-name label in 1992. Maison de Haute Couture until 2007, the brand JEAN-LOUIS SCHERRER concentrated on Couture ready-to-wear valuated brand in signing licenses for exclusive products, The brand is worldwide known for french elegance.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.jean-louis-scherrer-aujourdhui.com/'),
('Vera Wang', 'Vera Wang is an American fashion designer of Chinese descent who is most famous for her bridal gowns. Wang originally trained as a figure skater and competed professionally, but when she didn''t make the Olympics team, she left the sport and entered the fashion industry, becoming Vogue''s youngest editor ever, at age 23. The Vera Wang line has expanded to include eyeglasses, shoes, fur, home goods and and ready-to-wear. Fragrances are offered in conjunction with Coty.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.verawang.com'),
('J. Del Pozo', 'Jesus Del Pozo was a Spanish fashion designer born in Madrid in 1946. Opening his first boutique in 1974, Del Pozo was embarking on his career at the same time as Spain was beginning to transition from the dictatorship of Franco to democracy. The change in politics coincided with a change in social values now described as La Movida. Del Pozo, as an artist and designer, played an important part in this ''Movement'' and was regarded as a key influence in the modernization of Spanish style. Perfumes became an important piece of the Del Pozo brand''s offering, with Halloween (1997) becoming an international best-seller and spinning off a series of limited editions and flankers in future years.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.perfumesydiseno.com'),
('Perris', 'The Perris Monte Carlo Collection was born to intrigue you by its diverse and exquisite breadth of fragrances created by using the most noble of raw materials. In every culture gold represents power, wealth, luxury, success, durability... Gold is the color of prestige and it is even a reference in terms of quality (jewelry). Gold is everywhere : home design, clothing, accessories, fashion, perfumery...', 'Monaco', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://perrismontecarlo.com/'),
('Shiseido', 'Shiseido Company, Limited is a Japanese multinational cosmetic company founded in Tokyo, Japan in 1872. Its product categories consist of: skin care, makeup, body care, hair care, and fragrances. The company is one of the oldest cosmetic companies in the world and celebrated its 150th anniversary in 2022. It is the largest cosmetic firm in Japan and the fifth largest cosmetic company in the world.', 'Japan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://corp.shiseido.com'),
('Paris Hilton', 'Paris Hilton is an American socialite, heiress, media personality, businesswoman and model. Great-granddaughter of Conrad Hilton, who founded the international hotel chain Hilton Hotels, Paris Hilton first rose to fame through her work as a fashion model, but her lavish lifestyle and social exploits soon garnered more work and attention than her modeling career. In 2004, Hilton launched a perfume line in conjunction with Parlux. Her first fragrance, Paris Hilton for women, became an international best-seller, and was soon followed by a men''s fragrance of the same name. As of 2020, Her perfume line alone has brought in over US$2.5 billion in revenue.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://parishilton.com'),
('Angel Schlesser', 'Angel Schlesser is a renowned Spanish designer, who created in minimalistic style. The ANGEL SCHLESSER brand is known for its elegant, sophisticated, and minimalist style. Its designs focus on simple lines, clean cuts, and tailoring that accentuate the female figure. Over the years, ANGEL SCHLESSER has expanded its product range beyond clothing to include perfumes and accessories.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.angelschlesserparfums.com/en/'),
('Kenzo', 'Kenzo is a French luxury fashion house founded in 1970 by Japanese designer Kenzo Takada. Kenzo is credited with bringing Japanese fashion to the rest of the world, and his unique designs represent a mix of traditional Japanese lines with influences of nature and multi-culturalism. Kenzo Parfums'' first official release was 1988''s Kenzo for Women, a scent whose name was later changed to ça sent beau. A series of successful fragrances for men and women have since been offered, including the company''s flagship scent, the ground-breaking Flower by Kenzo.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.kenzo.com'),
('The Beautiful Mind Series', 'The Beautiful Mind Series celebrates women - not in the conventional way of the fragrance industry, as objects of desire - but for their intelligence and creativity. The Beautiful Mind Series is a new fragrance brand. Designer Geza Schoen initiated The Beautiful Mind Series, working with outstanding women in different creative fields to construct fragrances dedicated to the power of the female mind.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Sofia Vergara', 'Launched by the design house of Sofia Vergara. The fragrance includes notes and scents favored by the actresses, representing her true olfactory signature. The composition is announced as a juicy floral - oriental.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Salvatore Ferragamo', 'Salvatore Ferragamo S.p.A., doing business as Ferragamo is an Italian luxury fashion house focused on apparel, footwear, and accessories headquartered in Florence, Italy. It specializes in designing and manufacturing footwear and leather goods, which together account for over 86% of its revenue. The remaining products include ready-to-wear, silk products, fashion accessories, and licensed eyewear, watches, and perfumes. The unique, exclusive design which has always distinguished the Group''s products is obtained by combining style, creativity and innovation with the quality and craftsmanship typical of Italian-made goods.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ferragamo.com'),
('Michael Kors', 'Michael Kors is an American fashion designer celebrated for his womenswear collections. Michael Kors'' namesake company produces a range of products under Michael Kors Collection, MICHAEL Michael Kors and Michael Kors Mens, including accessories, footwear, watches, jewelry, ready-to-wear and a full line of fragrance products.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.michaelkors.com'),
('Marina De Bourbon', 'Princess Marina de Bourbon was married to a descendant of the Bourbon dynasty, one of the oldest and most traditional families of France. With her own hands, Marina created a line of perfume for sophisticated women who appreciate the traditional French way of life. Today, Marina works in the accessories business, and has a number of shops around the globe, mainly in Japan.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Ralph Lauren', 'Ralph Lauren is an American fashion designer known for his popular Polo line and other lines of clothing, accessories and home decor. Ralph Lauren is known for marketing and distributing products in four categories: apparel, home, accessories, and fragrances. Ralph Lauren Fragrances give the wearer yet another opportunity for personal expression through timeless style.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ralphlauren.com'),
('Justin Bieber', 'Justin Bieber is a Canadian pop singer, who was very young when he became a popular teen star. The official description of this perfume uses epithets such as energetic, sexy and refreshing, while the composition is announced as a luminous floral-fruity-musk. Justin chose the key motif for this perfume because of its symbolism, trying to tell his fans to always believe in their dreams.', 'American', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Moschino', 'Moschino is an Italian luxury fashion house that was founded in 1983 by Franco Moschino in Milan. The brand is known for its colorful, playful, and eccentric designs, often incorporating social commentary and over-the-top, campy aesthetics. It offers three lines: Moschino (men''s and women''s clothing), Moschino Cheap and Chic (women''s secondary line), and Love Moschino. The company also offers accessories, jewelry, cosmetics, and fragrances.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.moschino.com'),
('Oscar De La Renta', 'Oscar de la Renta was a Dominican fashion designer who established his fashion firm in New York. The brand is known for combining old-world craftsmanship with modern designs, often recognized for its classicism and romance. The house was founded in 1965 in New York, producing ready-to-wear collections, and later expanded into home furnishings and fragrances.', 'Dominican Republic', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.oscardelarenta.com'),
('Carven', 'Carven is a French perfume maker established in 1945, known for timeless and enchanting perfumes for women and men. Inspired by the brand''s history and DNA, Carven Parfums focuses on elegance and simplicity, creating fresh, classic, and impertinent feminine and masculine fragrances.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('One Direction', 'One Direction, also known as 1D, was an English-Irish pop boy band formed in London in 2010. The group consisted of Niall Horan, Zayn Malik, Liam Payne, Harry Styles, and Louis Tomlinson. Formed on British singing competition The X Factor in 2010. The band went on an indefinite hiatus in 2016.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.onedirectionmusic.com'),
('Dkny', 'DKNY is an American fashion house based in New York City, founded in 1984 by Donna Karan. The company specializes in a wide range of fashion products, including clothing, footwear, accessories, and fragrances. DKNY was founded in 1989 as a younger, more affordable diffusion line to run alongside her existing Donna Karan New York label.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.dkny.com'),
('Britney Spears', 'Britney Spears is an American recording artist and entertainer. Britney Spears markets fragrances under her name in conjunction with Elizabeth Arden. Her first fragrance, Curious, was introduced in 2004 and became a best-seller.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Braccialini', 'Braccialini is an Italian leather accessories company founded in 1954 and based in Florence, Italy. The company operates in 40 countries with 50 mono-brand stores globally.  The brand combines traditional craftsmanship with innovative designs to create unique and vibrant pieces known for their whimsical and artistic approach, showcasing intricate details and high-quality materials.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.Braccialini.com'),
('Bottega Veneta', 'Bottega Veneta is an Italian luxury fashion house based in Milan, Italy. Its product lines include ready-to-wear, handbags, shoes, accessories, jewellery and fragrances. The brand is known and recognised worldwide for its signature weaving design style - more professionally known as the “Intrecciato”. The Bottega Veneta philosophy is rooted in restraint, subtlety and discretion.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.bottegaveneta.com'),
('Beyonce', 'Beyoncé Giselle Knowles-Carter is an American singer, songwriter, actress and businesswoman. She rose to fame in 1997 as a member of Destiny''s Child. Beyoncé''s career shifted after forming her own management company Parkwood Entertainment, creating monocultural events through acclaimed concept albums. In February 2024, Beyoncé launched her hair care brand Cécred.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.beyonce.com'),
('Hayari', 'Hayari Parfums is a French fragrance brand by fashion designer Nabil Hayari. Launched in 2011, the brand creates perfumes combining French style and oriental aesthetics.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Balmain', 'Balmain is a French luxury fashion house founded in 1945 by Pierre Balmain. Known for its haute couture and ready-to-wear collections, Balmain blends classic Parisian elegance with modern, often edgy, designs. The brand has over 50 stores worldwide and its primary flagship is located on Rue Saint-Honoré in Paris.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.balmain.com'),
('Adrienne Vittadini', 'Adrienne Vittadini is a fashion brand founded in 1979 by the eponymous American designer of Hungarian origin. The brand is known for modern sophistication, effortless elegance, and ease. It offers knitwear in vibrant colors and rich textures and unexpected details, including accessories, eyewear and perfumes.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://adriennevittadini.com'),
('NÃ‚Â°4711', '4711 is a traditional German Eau de Cologne by Mäurer & Wirtz, produced in Cologne since at least 1799. The brand is known for its Original Eau de Cologne, which has used the same formula for more than 200 years. The original 4711 store at Glockengasse 4 in Cologne is a popular tourist attraction.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.4711.com'),
('L''Arc', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Loewe', 'Loewe is a Spanish luxury fashion house specializing in leather goods, clothing, perfumes, and accessories. Founded in Madrid in 1846, it is one of the oldest luxury brands and has been part of LVMH since 1996. Loewe is known for its focus on craft and expertise with leather.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.loewe.com'),
('Victoria''s Secret', 'Victoria''s Secret is an American lingerie, clothing, and beauty retailer. Founded in 1977, it is known for its lingerie, fragrances, and the Victoria''s Secret Fashion Show. The brand aims to make lingerie glamorous and has greatly impacted the lingerie world.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.victoriassecret.com'),
('Ferrari', 'Ferrari S.p.A. is an Italian luxury sports car manufacturer based in Maranello. Founded in 1939 by Enzo Ferrari, the company is known for its high-performance sports cars and its iconic prancing horse logo. Ferrari is synonymous with game-changing performance and unparalleled elegance.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ferrari.com'),
('Amouage', 'Amouage is an international luxury fragrance brand founded in 1983 in Oman. Known for using the finest ingredients, Amouage creates handmade and skillfully blended perfumes. The brand is based on the art of gift-giving, with each perfume considered a gift from kings.', 'Oman', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.amouage.com'),
('Tiffany & Co', 'Tiffany & Co. (Tiffany''s) is an American luxury jewelry and specialty design house headquartered in New York City. Founded in 1837, Tiffany is known for its luxury goods, particularly its sterling silver and diamond jewelry. It is also known for pioneering the first direct mail catalog.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.tiffany.com'),
('Perry Ellis', 'Perry Ellis is an American designer fashion clothing brand owned by Perry Ellis International. Founded by Perry Ellis in 1978, the brand offers a broad line of high-quality men''s and women''s apparel, accessories, and fragrances. The brand is known for a modern twist on timeless American style.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.perryellis.com'),
('Paloma Picasso', 'Paloma Picasso, born Anne Paloma Ruiz-Picasso y Gilot in Paris, is a fashion and jewelry designer and businesswoman, known for her work with Tiffany & Co. and her signature perfumes. Her designs are often described as bold, chic, and incorporating vibrant colors and geometric forms. In 1984, she launched her first perfume, "Paloma", in collaboration with L''Oréal, intended for strong women like herself.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mauboussin', 'Mauboussin is a French jewelry and fragrance house founded in 1827 in Paris. Known for capturing the Art Deco movement''s aesthetic, the brand gained a worldwide reputation for innovation and expertise in colored stones. The Mauboussin logo, a four-branched shooting star, symbolizes light, preciousness, uniqueness, and timelessness. The brand creates jewelry, watches, and accessories for both women and men. In fragrances, Mauboussin offers a range of perfumes and eaux de parfum, often emphasizing natural raw materials.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mauboussin.fr/en/'),
('Lolita Lempicka', 'Lolita Lempicka, founded by Josiane Maryse Pividal in 1985, is a brand that has created a magical and enchanting world in fashion and fragrances. The brand launched its first fragrance in 1997, noted for its distinctive and committed signatures, and has become known for its vegan and cruelty-free precepts. Inspired by fairy tales, the brand is known for capturing the radiance of femininity.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mercedes Benz', 'Mercedes-Benz Parfums embodies modernity and luxury, with fragrances created in collaboration with master perfumers such as Olivier Cresp. The brand''s fragrances for men and women offer a blend of strength and delicacy, romanticism and power, mystery and sophistication. The brand''s fragrances stand apart as high-end products, with attention to detail evident in the choice of ingredients and unique bottle designs.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mercedes-benz-parfums.com/en/'),
('Laura Biagiotti', 'Laura Biagiotti is a prominent name in Italian fashion, known as the "Queen of Cashmere" for her love of this luxurious fabric. The brand, founded in the 1960s, is celebrated worldwide for its high-quality clothing, collections, perfumes and its patronage of the arts. Laura Biagiotti''s perfumes are inspired by nature and Italian culture, often incorporating fresh and floral notes.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Korloff', 'Korloff is a French luxury brand established in 1978, known for its jewelry, watches, and fragrances. The brand takes its name from the Korloff Noir, a legendary black diamond. Korloff is known for its opulent designs and the use of precious gemstones and diamonds. Korloff Paris also offers a range of unisex scents with elegant packaging.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Kim Kardashian', 'Kim Kardashian is an American TV personality, actress, and model who launched her signature fragrance in 2009. Her perfumes are designed to capture sensuality and femininity, producing a spectacular floral fragrance experience. The scents often feature a blend of luminous, sweet opening notes, intoxicating floral middle notes, and sensual aromas in the base.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Jimmy Choo', 'Jimmy Choo is a luxury fashion brand based in London, known for its high-end shoes, handbags, and accessories. The brand''s perfumes are synonymous with elegance, sophistication, and glamour. Jimmy Choo fragrances are designed to evoke a sense of confidence, style, and femininity, with their exquisite floral, fruity, and woody notes.', 'Uk', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Halloween', 'Halloween Perfumes, launched in 1997, is a brand known for its mysterious and youthful spirit. The fragrances are designed to embody the spirit of Halloween, with a blend of violet, banana leaf, and sea notes, creating a floral scent with herbal undertones. The brand offers both women''s and men''s fragrances.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Guy Laroche', 'Guy Laroche, founded in 1957, is a French fashion brand renowned for its refined and sophisticated style, understated elegance, and contemporary designs. The brand offers a range of products, including clothing, watches, jewelry, accessories, and fragrances. Guy Laroche designs are for sophisticated men and women with an appreciation for French style.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Donna Karan', 'Donna Karan is an American fashion house founded in 1984 by Donna Karan and Stephan Weiss. Karan worked for 15 years at Anne Klein, including 10 as its head designer. The company specializes in a wide range of fashion products, including clothing, footwear, accessories and fragrances. In 1988, Karan extended her women''s ''Donna Karan New York'' line by creating a less expensive clothing line for younger women, called DKNY. LVMH sold Donna Karan International, with the ''Donna Karan'' and ''DKNY'' brands, to the G-III Apparel Group in 2016.', 'U.S.', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.dkny.com'),
('Diptyque', 'Diptyque Paris is a French luxury fragrance brand headquartered in Paris, France. Founded on 34 Boulevard Saint-Germain by a trio of French designers, its brand name is derived from the Ancient Greek word Diptych. The company produces perfumes (colognes), scented candles, skincare, soaps, and oil diffusers. The original boutique still operates at the same location in Paris, and the brand has 124 boutiques worldwide. In 2005, Diptyque was bought by London-based private equity firm Manzanita Capital.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.diptyqueparis.com'),
('Costume National', 'Costume National is an Italian fashion house, founded in 1986 by Ennio Capasa and his brother Carlo Capasa. Costume National''s head office is located in Milan, Italy. The company produces clothing under the brands Costume National, Costume National Homme (for men) and C''N''C as well as scents. The brand started to create its first perfumes in 2002.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.costumenational.com'),
('Marc Jacobs', 'Marc Jacobs is an American fashion designer. He is the head designer for his own fashion label, Marc Jacobs. Jacobs was on Time magazine''s "2010 Time 100" list of the 100 most influential people in the world.  Marc Jacobs created Marc Jacobs International with Robert Duffy in 1984, basing the brand on two very simple concepts: a love of fashion and a commitment to quality. Part of a generation that''s conscious of the world around it, sensitive to humanitarianism and social entrepreneurship, Marc Jacobs has made its mark as rebellious, unpredictable, original, unique, and authentic all at the same time.', 'U.S.', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.marcjacobs.com'),
('Micallef Studio', 'Micallef Studio is one of the largest brands in the world of perfumes, originated in France and was first released in 1996.  M.Micallef Parfums was founded in 1996 in Grasse, the world capital of perfumes. Launched with passion through the alchemy between Martine Micallef and Geoffrey Nejman, this family business developed the Art and Perfume concept.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Nina Ricci', 'Nina Ricci is a fashion house founded by Maria "Nina" Ricci and her son Robert in Paris in 1932, and owned by the Spanish beauty and fashion group Puig since 1998. Nina Ricci designs soon became known for the refined, romantic, always feminine feeling Maria adds to all of her collections. Robert Ricci created an in-house perfume division in 1941. Nina Ricci represents a world where women can discover and display their best selves. Join a brand whose artistic sensitivity creates a unique style that blends simplicity, purity and creativity.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ninaricci.com'),
('Agent Provocateur', 'Agent Provocateur is a British lingerie retailer founded in 1994 by Joseph Corré and Serena Rees. Agent Provocateur is a luxury lingerie line established in the UK in 1994. Directional, luxurious and sensual Agent Provocateur lingerie is designed to empower the wearer.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.agentprovocateur.com'),
('Abercrombie & Fitch', 'Abercrombie & Fitch Co. (A&F) is an American lifestyle retailer, founded in 1892 which focuses on contemporary clothing targeting customers in their early 20''s to mid 40''s. Headquartered in New Albany, Ohio, the company operates four offshoot brands: Abercrombie Kids, Your Personal Best, Hollister Co., and Gilly Hicks with 780+ company operated stores across its brands, as of Q4 2024.', 'U.S.', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.abercrombie.com'),
('Elizabeth Taylor', 'Elizabeth Taylor was a British-American actress whose film career spanned nearly sixty years. Elizabeth Taylor was also a fashion icon with a passion for fine jewelry, which served as inspiration for the perfume line she would launch with Elizabeth Arden. The first fragrance in the line, women''s scent Passion, debuted in 1987.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://elizabethtaylor.com'),
('Comme Des Garcons', 'Comme des Garçons (French for ''Like Boys''), also CDG for short, is a Japanese fashion label based in Paris, founded by Rei Kawakubo. The label was started in Tokyo by Rei Kawakubo in 1969 and established as a company in 1973. The brand''s name was inspired by Françoise Hardy''s 1962 song "Tous les garçons et les filles".', 'Japan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.comme-des-garcons.com'),
('La Martina', 'La Martina is an Argentine sports and leisure clothing manufacturer founded in 1985 by Lando Simonetti. It is known for its focus on polo technical equipment, clothing, and accessories, drawing stylistic inspiration from the world of polo. The brand is considered a quintessential international polo brand, representing elegance, prestige, and the traditions of polo. La Martina is the official supplier for various polo teams and international tournaments.', 'Argentina', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://lamartina.com'),
('Fragrances Hubert Fattal', 'Fragrances Hubert Fattal is a Lebanese brand that creates unisex perfumes and scented candles, each inspired by Hubert Fattal''s childhood in his native country. The brand is known for its Mediterranean oriental identity, using essential oils from Grasse in France. Hubert Fattal, the fourth-generation head of a 122-year-old brand distribution company, launched the namesake brand to express himself creatively.', 'Lebanon', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Missoni', 'Missoni is an Italian luxury fashion house based in Varese, known for its colorful knitwear designs. The company was founded by Ottavio ("Tai") and Rosita Missoni in 1953. Missoni has expanded to include knitwear, leather, cotton, swimwear, and home furnishings. The brand''s genesis lies in the shared dream of Ottavio and Rosita, who transformed a modest venture into knitwear into an international brand.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.missoni.com'),
('Ramon Monegal', 'Ramon Monegal is a niche perfume brand from Barcelona, symbolizing Spanish perfumery. The brand was founded by Ramon Monegal, a fourth-generation perfumer from the Monegal family, who founded the iconic Myrurgia in 1916. Ramon Monegal''s perfumes showcase artisan methods and unrestricted creativity, raising perfume to the level of art. His fragrances are inspired by literature, turning words into notes and stories into compositions.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.ramonmonegal.com'),
('Joop', 'Joop GmbH, branded JOOP!, is a German luxury fashion house specializing in contemporary clothing and cosmetics. The company was founded as a designer label by German fashion designer Wolfgang Joop in Hamburg, Germany, in 1986. Joop offers upscale womenswear, menswear, kid''s clothing, accessories, and home articles. The company is most notable for its vast fragrance range originally launched in 1987.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.joop.com'),
('Floris London', 'Floris is a London-based perfumery house that has been in operation since 1730 and continues to be run by descendants of the founders. Originally founded by Juan Famenius Floris, Floris sold grooming and shaving products as well as perfumes. Royalty, historical figures, and celebrities have long been customers of Floris. Floris offers fragrances in four collections: Men''s fragrances, Women''s fragrances, the Classic collection, and the Private collection.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.florislondon.com'),
('Widian', 'WIDIAN is a perfume house founded by Ali Aljaberi in Abu Dhabi, UAE. WIDIAN perfumes present the luxurious oriental scents of Arabia blended with flowery and fruity aromas from around the world. The fragrances of the house are divided into two collections: Black and Gold. The Gold Collection includes more Oud- and Amber-based fragrances. Widian means Valley in Arabic', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Louis Vuitton', 'Louis Vuitton Malletier SAS, commonly known as Louis Vuitton, is a French luxury fashion house and company founded in 1854 by Louis Vuitton. The label''s LV monogram appears on most of its products, ranging from luxury bags and leather goods to ready-to-wear, shoes, perfumes, watches, jewelry, accessories, sunglasses, and books. Louis Vuitton is one of the world''s leading international fashion houses.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://louisvuitton.com'),
('Solinotes', 'Solinotes is a French fragrance brand that offers a range of perfumes and body care products. Solinotes specializes in creating fragrances designed for layering and blending, allowing customers to create their own personalized scents. Solinotes''s story is also the story of perfume and its perfumers.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Sisley', 'CFEB Sisley, better known as Sisley Paris, is an independent French luxury cosmetic, skin care, hair care, and perfume company. The firm develops products based on active ingredients derived from plants for different skin types and different uses: moisturizing, anti-aging, sun care, and makeup. In 1976, Hubert d''Ornano acquired the company, re-naming it Sisley in reference to the Impressionist painter.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.sisley-paris.com/fr-FR/'),
('Shakira', 'The brand ''__NULL__'' is associated with the famous singer Shakira. Her fragrances are designed to capture the essence of her energy, sensuality, and musicality, offering a range of scents that appeal to a broad audience.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Salvador Dali', 'Salvador Dali perfumes are inspired by the surrealist artist''s paintings and artistic vision. The fragrances often come in unique, artistic bottles and aim to capture the essence of Dalí''s surreal and imaginative world.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.salvadordali.com/'),
('Rue Broca', 'Rue Broca is a fragrance brand founded in 2015 known for its exclusive and trendsetting collections. As part of the Afnan Perfumes family, Rue Broca reflects a commitment to sophistication and style. The brand''s mission is to create perfumes that capture powerful memories and emotions, making each scent a personal journey. With an emphasis on quality and originality, Rue Broca uses the finest ingredients sourced from around the world to craft unique, luxurious fragrances at an accessible price point.', 'Uae', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Kenneth Cole', 'Kenneth Cole Productions, Inc. is an American brand founded in 1982 by Kenneth Cole. The company is known for its clothing, shoes, and accessories. The brand launched its first fragrances, Kenneth Cole for Men and Kenneth Cole for Women, in 2002. Kenneth Cole fragrances are offered in collaboration with Coty and Parlux. The brand is synonymous with daring yet classic aromas, designed for city living and appealing to the modern, sophisticated man and woman.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.kennethcole.com/'),
('Atkinsons', 'Atkinsons of London is a British perfume house founded in 1799. The brand was relaunched in September 2013 after a long dormant period off the market. Atkinsons has been the official perfume of the British Royal Court. In 2020, Atkinsons was acquired by EuroItalia, continuing a story that, while maintaining solid roots in a glorious past, renews and transforms itself to meet the needs of contemporary customers.', 'Uk', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.atkinsons1799.com/'),
('Exuma Parfums', 'Exuma Parfums is a new fragrance brand that recently emerged in Poland in 2018. The brand released a group of innovations and fragrant creations with a modern and distinctive character. Designer Exuma Parfums has 19 perfumes. Exuma Parfums fragrances were made in collaboration with perfumers Bertrand Duchaufour, Jordi Fernández, Maxime Philippe, Daniel Visentin, Dominique Moellhausen, Marie Huguenot and Serge de Oliveira.', 'Poland', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Ideo Parfumeurs', 'Ideo Parfumeurs, based in Beirut, Lebanon, draws inspiration from the city''s creative spirit and contradictions to create sophisticated, long-lasting scents. Ludmila Bitar founded the brand to offer a fresh perspective on perfume creation, blending Middle Eastern ties with European culture. Their fragrances embody individuality, independence, and timeless elegance.', 'Lebanon', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Bon Parfumeur', 'Bon Parfumeur is a French fragrance brand founded in 2017 by Ludovic Bonneton. The brand offers a range of unisex scents designed to be mixed and matched to create new fragrances. Each fragrance is ethically made in France with carefully examined ingredients. Bon Parfumeur aims to revive Parisian perfumery with a creative and community-focused approach.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Banana Republic', 'Banana Republic is an American upscale clothing and accessories retailer owned by The Gap. Founded in 1978 by Mel and Patricia Ziegler, it was originally named Banana Republic Travel & Safari Clothing Company. In 1983, Gap purchased the company and rebranded the stores to achieve a more upscale image. Banana Republic is a storyteller''s brand, outfitting the modern explorer with high-quality, expertly crafted collections and experiences to inspire and enrich their journeys.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://bananarepublic.gap.com/'),
('Avon', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Afnan', 'Afnan Perfumes, established in 2007 by Imran Fazlani in the United Arab Emirates, blends Middle Eastern perfumery traditions with modern twists, offering a diverse range of luxurious scents for men, women, and unisex wearers worldwide. Known for series like 9AM/9PM and Supremacy, Afnan provides high-quality, budget-friendly alternatives to designer fragrances, emphasizing craftsmanship and creative packaging.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://afnan.com'),
('Karl Lagerfeld', 'Karl Lagerfeld is a high-end fashion brand named after the renowned German designer, photographer, and creative director Karl Lagerfeld. The brand embodies Parisian flair with rock-chic elements, offering a wide range of products, including ready-to-wear, accessories, shoes, and fragrances for men and women. It is known for its simple, monochromatic designs that often include sunglasses, high collars, and fingerless gloves.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.karl.com'),
('Vertus', 'VERTUS, established in 1996, is a French niche perfume brand known for perfecting "The Art of Scent". It embodies a sensual approach to creating signature scents in France. VERTUS is known for its family of rare fragrances, artfully blended with unique quality. Their commitment to innovation has drawn attention from niche perfume lovers, with fragrances enjoyed in 4 continents.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertusparfum.com/'),
('Ulric de Varens', 'Ulric de Varens is a French marketing company founded in 1983 by Ulric Viellard, offering creative and original perfumes at affordable prices, targeting a market of ages 20 to 35 years. Their products are marketed in France mainly in grocery stores, with select boutiques in large cities, and are also available in Europe, Asia, and Argentina. In addition to fragrances, they produce body care products, cosmetics, home fragrances, candles, and jewelry.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://ulric-de-varens.com'),
('Ted Lapidus', 'Founded by Edmond "Ted" Lapidus in 1951, Ted Lapidus is a French fashion house known for its unisex style and military-inspired designs. Lapidus joined the Chambre syndicale de la haute couture in 1963 and gained popularity with stars like Twiggy and John Lennon. The brand expanded into accessories and fragrances, with the fragrance license transferring to the Jacques Bogart Group in 1983. Ted Lapidus passed away in 2008, and in 2000, the label officially ended its couture division to focus on accessories and fragrances.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Stephane Humbert', 'Stéphane Humbert Lucas 777, founded by Stéphane Humbert Lucas in 2012, is a French perfume house known for its luxurious, oriental-themed fragrances created with precious essences. The brand name symbolizes spirituality, protection, and luck. Lucas, also the creator behind Nez a Nez and SoOud, infuses his perfumes with artistic sensibility, drawing inspiration from painting, literature, and music, and is known for his synesthesia, where sight triggers olfactory perception.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://stephanehumbertlucas.com/'),
('Junaid Perfumes', 'Junaid Perfumes, officially Syed Junaid Alam, is a Bahraini brand established in 1910, renowned for high-quality Oud oils, Bakhoors, and Arabic and French fragrances. With over 100 retail outlets across 5 countries and a growing global presence, the brand is known for its devotion, innovation, and excellence. Fragrance Arabia is an extension of Junaid Perfumes that sells to the USA, Canada & Mexico.', 'Pakistan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://junaidperfumes.com'),
('Lootah', 'Lootah Perfumes is an Emirati brand that celebrates the UAE''s heritage through perfumery. Originating from a family''s passion since the 1950s, it blends Emirati oriental fragrances with French perfumery. With the first boutique opening in 2012, Lootah Perfumes offers fragrances, fragrant oils, and incense, using fine ingredients.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://lootahperfumes.com/'),
('Moresque', 'MORESQUE is an Italian niche perfumery brand that combines Italian design and craftsmanship with the art of Arabic perfumery. Each fragrance is a jewel made in Italy, reflecting a passion for detail and Moorish style. Cindy Guillemant, the founder, blends Italian taste and Arabic charm, creating unique and timeless fragrances.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Nasamat', 'Nasamat Najd is a modern Saudi luxurious perfume house. Nasamat Najd is a promising and modern Saudi luxurious perfume house. Designer Nasamat Najd has 10 perfumes in our fragrance base. Nasamat Najd is a new fragrance brand. The earliest edition was created in 2020 and the newest is from 2024. Nasamat Najd fragrances were made in collaboration with perfumers Charlotte Jullien and Dominique Moellhausen.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Palquis', 'Palquis pays tribute to the Queen of Sheba, legendary sovereign of the Eastern kingdom. Many names have been dedicated to her like Palquis, Balkis or even “Creature of Heaven”. Idolised and admired by her people beyond the frontiers, the Queen of Sheba was infinitely beautiful. In the golden age of lost paradises, her territories mainly extended to the heart of the Arabian Peninsula. In the hollow of the red sea and surrounded by the Euphrates to the north, her lands were full of riches, perfumes, incense, myrrh, amber and spices. The Romans claimed that it was also the land of the Phoenix, a symbol of absolute rebirth. A genuine authentic ballade in an olfactory oasis, Palquis celebrates this dreamlike world through prestigious, refined creations that combine noble materials and ancestral know-how. Palquis is a new fragrance brand.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Orientica', 'Orientica Perfumes is a brand that epitomizes refinement and luxury through its exquisite range of fragrances. Each perfume is crafted to tell a unique story, adding a touch of magnetism and grandeur to your image. Orientica is dedicated to conceptualizing a fusion of superior ingredients to create a diverse array of luxury fragrances that cater to connoisseurs and newcomers alike. Not just limited to perfumes, Orientica also offers luxurious gift sets that make for the ideal present for any occasion. The brand''s commitment to quality extends to its packaging, ensuring that the experience of unboxing is as delightful as the scent itself.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Miris', 'Miris is a Swedish company developing, manufacturing, marketing and selling instrument and solutions for human milk analysis. The company was established in 2001 focusing on the application of analysing dairy milk. In 2006 Miris launched its first instrument for human milk analysis as the field of individual nutrition of preterm babies became a standard in the neonatal intensive care units in Sweden. Since then, the company has built unique competence and expertise in this field. We market and distribute the product portfolio for Miris HMA - Human Milk Analyzer (HMA) containing a complete set of services and consumables.', 'Sweden', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Liz Claiborne', 'Liz Claiborne has been a leader in the fashion industry for over 50 years. Founded by the iconic designer Liz Claiborne in 1976, the company became known for its polished, professional clothing for working women. Though Liz Claiborne herself retired in 1989, her name lives on through the company''s extensive brands. Today, Liz Claiborne offers stylish, versatile clothing, shoes, and accessories for women. The brand provides affordable luxury, using high quality materials and thoughtful design details. Signature Liz Claiborne styles like tailored blazers, wrap dresses, loafers and tote bags have remained relevant decade after decade. Staying true to its founding ethos, the Liz Claiborne brand continues to outfit polished professionals. The clean, classic aesthetic transitions effortlessly from desk to dinner. Customers trust Liz Claiborne to provide real value at an accessible price point. Fans appreciate the attention to fit, fabric and finishing given to every Liz Claiborne garment. Though trends come and go, Liz Claiborne remains committed to producing timeless, versatile wardrobe essentials. With Liz Claiborne, customers can always count on finding sophisticated style, ease of wear and excellent quality.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.lizclaiborne.com/'),
('Kilian', 'Kilian Hennessy creates unique, unexpected perfumes that embody the utmost refinement and luxury through stories and emotions. Born into one of France''s most illustrious liqueur dynasties, this perfume artist transforms the sensitivity and creative flair inherited from his ancestors and applies them to the world of fragrances. His quest for absolute luxury and his bold approach and revolutionary define the eponymous Kilian Paris brand. Kilian Paris perfumes are a concentration of stories and emotions. the Oak barrels that line the ancient vaults of the Hennessy dynasty. Steeped in sugar, alcohol and wood, the evaporation of scents emanating from these casks, known as the “angel''s share”, created the childhood sense memory that would one day influence Kilian Hennessy''s life''s work.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Jo Malone', 'Jo Malone London is a British fragrance and lifestyle brand, with a contemporary point of view. Timeless and elegant but always infused with a charming dash of wit and whimsy. From the start, their colognes have been revolutionary in their elegant simplicity and pioneering in their use of ingredients. Jo Malone London has evolved to become synonymous with coveted scents and luxurious products for bath, body and home.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.jomalonelondon.com'),
('Jadeed', 'We are a Jadeed a group of innovators who always felt some pain due to absence of innovate yet affordable energy/technology solutions which reduces power/water consumption. We Market, Adopt, research & develop, manufacture digital and smart energy innovative solutions in order to ensure providing them in a cost effective way to our end user. Aims to provide safe and sustainable alternative green energy solutions to reducing temperature & carbon emissions, spread green environmental awareness, spreading awareness of energy saving, also contribute to reduce ambient air pollution by reducing fuel consumption adopting a healthy lifestyle.', 'Egypt', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Issey Miyake', 'Since designer Issey Miyake presented his first collection in 1971, ISSEY MIYAKE has been designing and making clothing that explores the relationship—the ease and ma (the unfilled space)—between the wearer''s body and the fabric of the wear, which is founded upon the brand''s unwavering approach to the concept of a piece of cloth, thereby developing clothing that is universal and unbound by the Western vs. Eastern conventions of clothing design. The vision of Issey Miyake Parfums is to offer unique creations, combining both nature and technology resources and materials. It is through this dual use of nature and synthesis that the perfumer''s creative palette is at its widest and gives birth to bold, singular and surprising new fragrances.', 'Japan', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.isseymiyake.com/'),
('Giorgio', 'Giorgio Armani S.p.A., commonly known as Armani, is an Italian luxury fashion house founded in Milan by Giorgio Armani which designs, manufactures, distributes and retails haute couture, ready-to-wear, leather goods, shoes, accessories, and home interiors. It is considered Italy''s third-biggest fashion group behind Gucci and Prada. Giorgio 1958''s history begins many years ago in the Marche region, central Italy, the center of excellence in the realization of all the phases in the production of footwear. The Sacchetto (slip-lasting method) construction, the Blake stitching, and the hand buffing are just some of the artisanal handcrafting processes used for the Giorgio 1958 shoes. Long and complex operations that require a careful and meticulous execution, but confer that classic Italian Style touch, between elegance, tradition, innovation, and comfort.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.armani.com'),
('Gemina.B', 'Gemina.B is an international brand that has sought to satisfy its customers for years by offering diversity in its products in terms of design, fragrance families, prices, in addition to constantly making up new ideas. Extensive research has been conducted upon the aesthetic design of its products while the brand is keen on adding a great value to all of its fragrances to become unique and symbolize imagination, dreams and desire. The brand surrounded itself with the best perfumers and was always interested in developing its fragrances.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Diesel', 'Diesel is an innovative international lifestyle company, founded by Renzo Rosso in 1978. Rooted in denim mastery and evolved into being a leader in premium fashion, Diesel is now a true alternative to the established luxury market. Since 2020, Diesel''s collections are overseen by creative director Glenn Martens, including apparel, accessories and a wide range of lifestyle collaborations: from fragrances, watches and jewelry to interior design and real estate projects with Diesel Living. Discovering, supporting, and fostering creativity is part of Diesel DNA.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.diesel.com/'),
('Carrera Jeans', 'Carrera Jeans was born in the 1970s as part of the larger Carrera brand, which originally made its name in sportswear and sunglasses. The denim division quickly gained a reputation for creating high-quality, stylish jeans that combined Italian craftsmanship with a relaxed, casual aesthetic. By the 80s and 90s, Carrera Jeans became synonymous with street style, boasting bold, eye-catching logos and a fit that perfectly suited the decade''s love for baggy jeans and oversized looks. Carrera Jeans went on to become a key player in the casual wear market, with many fans across Europe and beyond.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://carrerajeans.com/'),
('OJAR', 'OJAR, founded by Sheikha Hind Bahwan, is a fusion of fragrances from East and West. Created as a reflection of modern and traditional harmony, the brand pays tribute to the art and rituals of Middle Eastern perfume making. The Omani founder is behind the fragrance collection, design, and visual campaign. ''I see perfume as a lifestyle, it''s a signature you carry wherever you go'' - said the visionary Hind Bahvan. OJAR comes from the word HOJARI, which is widely considered to be the highest quality incense resin in the world. It is located in the mountains of Dhofar in Oman.', 'Oman', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Caesars World', 'Caesars World Inc. was a hotel and casino operator. It began as Lum''s Inc., owner of the Lum''s chain of restaurants. It shifted into the gaming business with the purchase of Caesars Palace on the Las Vegas Strip in 1969, selling off the restaurants and changing its name. Caesars grew to eight casinos and resorts over the years, until going through a series of ownership changes beginning in 1995 and was ultimately absorbed by Park Place Entertainment in 1999.', 'U.S.', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Bond No 9', 'Bond No. 9 is an American, New York-based perfume house launched in 2003 by Laurice Rahmé. The products are for both men and women. Since then, the fragrance house has been creating fragrances that celebrate New York City''s neighbourhoods and showcase the city''s unbreakable spirit. Bond No. 9 is staunchly independent – allowing them the most freedom to work with new notes, non-conformist formulas, unique packaging concepts. The brand aims to restore the grand art of perfume blending. Each fragrance has been blended in New York, by a team of hand-picked perfumers.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.bondno9.com'),
('Black Dust', 'Black Dust Limited Edition Eau de Parfum for men is a 100 ml fragrance that blends oriental and woody elements for a bold and lasting impression. It opens with delicate notes of rose and oud, creating a rich and inviting introduction. The heart features a warm fusion of beeswax and honey, adding depth and sweetness to the composition. As the scent settles, the base notes of tobacco, amber, and sandalwood provide a robust and masculine foundation. While primarily designed for men, its complex aroma makes it appealing to women who appreciate intense, oriental fragrances, making it ideal for festive and special occasions.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('BCBG Max Azria', 'Founded in 1989, BCBGMAXAZRIAGROUP is the lifetime vision of one man: Founder, Designer, Chairman and Chief Executive Officer Max Azria. After years of success in designing women''s wear in his native Paris as well as Los Angeles, Azria decided to pursue his dream of launching a design house that spoke to the modern woman thus BCBGMAXAZRIA was born. Named from the French phrase bon chic, bon genre, a Parisian slang meaning good style, good attitude, the brand embodies a true combination of European sophistication and American spirit.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Authentic', 'Brand authenticity refers to the degree to which a brand is perceived as being real, genuine and trustworthy by its customers and stakeholders. It''s how transparent, honest and consistent is its messaging, actions and values — creating trust and loyalty with customers who believe in the brand and its ability to deliver on its promises.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Arabian Souvenir', 'The Brand Inspired by the culture and heritage of Arabia, arabian souvenir perfume was created to capture the illustrious scents of the Arab World and share them with you. The sweet scents of Damascus blend with the rich aroma of Saudi Arabian oud, the heady scents of Yemeni spices, leather and coffee, the warm, woody, sweet aroma of Jerusalem''s frankincense, and the exhilarating fragrant oils and attars of Baghdad; Arabian Souvenir embraces these captivating fragrances in an enchanting bottle and takes you on a breathtaking and intimate journey that transcends time and place.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Antonio Banderas', 'Antonio Banderas is a collection born of a collaboration by award-winning actor Antonio Banderas with the famous Spanish perfume house Puig. It is an extensive line of fragrances which started in 1997 and continues to release new scents until today. The brand has made it a point to design a fragrance for every personality.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Alyssa Ashley', 'Alyssa Ashley was founded in 1968 by Enrico Donati, an artist in America, seeking to create a brand that symbolized the modern approach to life in the 60s. The brand is known for its fragrance compositions of musk and elegant flower bouquets appealing to both men and women. The brand was born from the union of two art forms: the figurative and the perfumery art and developed as a Master in Perfumery, during an era of rebellion, where words like independence, female emancipation, freedom, guided entire generations.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Acqua Di Parma', 'Acqua di Parma is an Italian lifestyle and fashion company founded in 1916 by Carlo Magnani that produces fragrances, candles, bathrobes, and leather accessories. All of its ranges are exclusively made in Italy and distributed in 43 countries. The company is known for pairing Italian luxury with traditional craftsmanship.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Bath & Body Works', 'Bath & Body Works, founded in 1990 in New Albany, Ohio, is an American retail store chain that sells soaps, lotions, fragrances, and candles. It began as the beauty line for Express, Inc. The company has expanded across six continents and became the largest bath shop chain in the United States in 1997. Bath & Body Works aims to make the world a brighter, happier place through the power of fragrance.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.BathandBodyWorks.com'),
('Zadig & Voltaire', 'Zadig & Voltaire, founded in France in 1997 by Thierry Gillier, is a French fashion brand known for its distinctive blend of luxury and rock ''n'' roll aesthetics with an edgy, streetwise aesthetic. The brand got its name from a seminal work of French literature, and from its trail-blazing writer Voltaire whose ideas inspired his country''s revolution over 250 years ago. The brand is celebrated for its edgy yet casual style and is becoming a prominent player in the luxury fashion industry.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('V Canto', 'V Canto is an Italian perfume brand, a line of perfumes from the Cereria Terenzi Evelino brand created by Paolo and Tiziana Terenzi, inspired by the most enchanting love story ever written, a love for authentic deep roots and for the homeland. For over 700 years, the Terenzi family has lived near Gradara Castle, one of the most evocative in Italy. The collection depicts love for the native country and roots in a unique way inspired by Dante Alighieri’s “The Divine Comedy”.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('SAP', 'SAP (Systems, Applications, and Products) is the market leader in business process management software (ERP) providers. Based in Walldorf, Germany, SAP helps organizations efficiently manage their data and information flows. SAP primarily targets SMEs/ETIs, but the platform is also widely used in large organizations and covers all key areas within a company. Purchases, production, sales, marketing, finance, and human resources are all handled within a connected and intelligent platform.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Roja', 'Roja Parfums is an independent British perfumery house founded in 2011 in London by Perfumer Roja Dove. Roja Parfums create fragrances rich in personality, using luxury ingredients and craftsmanship to tell stories that resonate around the world. From signature scents to home collections, each piece is crafted using the finest quality raw materials. A Roja Parfums fragrance is an item to treasure.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Roos & Roos', 'Roos & Roos is a perfume brand brought to life by the dynamic mother-daughter duo, Chantal and Alexandra Roos. Roos & Roos is rooted in the unwavering link between music and perfume, an alchemy between the career of a musician and that of a woman who made her career in perfume. Roos & Roos is the twofold assertion of a family name shared by the creators. A mixture of the Parisian spirit and the French know-how excellence, Roos & Roos fragrances embody a singular vision of the luxurious and exceptional.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Joyau Unique & Sensoriel Parfums', 'Joyau Unique & Sensoriel Parfums is a leading perfume brand that embodies luxury and aromatic sophistication in its unique and amazing creations for men and women. Each scent is a masterpiece, evoking a tapestry of emotions and memories through luxurious blends of rare florals, rich woods, and sultry musks.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Jean Antoine', 'Jean Antoine is a brand that offers a range of luxurious and precious perfumes for all men and women looking for the highest levels of elegance and luxury. The company relies on the finest types of rare aromatic ingredients around the world. The brand offers a range of luxurious and precious perfumes for all men and women looking for the highest levels of elegance and luxury', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Gritti', 'Gritti Venetia is an Italian brand offering exquisite perfumes capturing the essence of luxury and elegance. The brand''s history is deeply rooted in the tales of Alvise Gritti, a noble alchemist and traveler from the 16th century, inspiring the passion and creativity behind each fragrance. Gritti perfumes embody the highest standards of quality and craftsmanship, with a diverse collection catering to every individual''s preferences. All fragrances are made in Italy in their own production facility in Bologna.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.grittifragrances.com'),
('Glenn Perri', 'Glenn Perri is a fragrance brand with a range of masculine scents. Some reviews suggest their fragrances are ''clone'' houses, creating scents similar to popular fragrances like Creed Aventus and Chanel Allure Homme Sport Extreme. Glenn Perri Unpredictable Noir Pour Homme smells like Aventus Creed clone very nice musky at the beginning but more fruity at the end.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Geparlys', 'Geparlys Parfums is a French fragrance brand. The Provence and City of Grasse in France has always been Geparlys'' number one choice. Well aware of the potential and environmental advantage of the region, Geparlys has grown, explored, and keeps cultivating to this day the most beautiful flowers of Grasse, the city that has now become an emblematic place of Geparlys'' history. In the quest for essence, the secret of wonderful fragrances lies in the heart of natural raw materials. For this reason, Geparlys has always used the most premium material for any of its olfactory creations.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://geparlys.com/'),
('Creed', 'Creed Fragrances is an Anglo-French multi-national niche perfume house, based in Paris. The House of Creed began in 1760 when a pair of scented leather gloves were delivered to King George III by a new London tailoring company. Creed has created fragrances for the discerning for over 260 years, shifting from its tailoring heritage into one of the world''s leading niche perfume houses. Creed prides themselves in using only the best quality ingredients in their perfume creations that are high in natural oils. Many of these fine ingredients used by Creed have been used in the world of perfumery for thousands of years.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://creedfragrance.com'),
('Kajal Perfumes Paris', 'Kajal Perfumes Paris is a fragrance house created out of a love for luxurious fragrances, drawing inspiration from the beauty world and the Orient. The name “Kajal” comes from the Arabic word “khajal,” meaning modesty, humility, and kindness. Kajal Perfumes Paris is registered in Dubai, where inspirations for creating compositions and beautiful, oriental bottles are born. The whole production takes place in France, the world''s home of perfumery, with traditional methods of extracting oils and maceration.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://kajal.pl'),
('Yantami', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Musk Alemarat', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Reef Perfumes', 'Reef Perfumes is inspired by the mystique and beauty of the Middle East, our perfumes capture the spirit of exotic ingredients, artisanal craftsmanship, and a deep-rooted passion for scents that tell a story. Each perfume is crafted using the finest raw materials sourced from around the globe, ensuring a unique and unforgettable scent profile. From the elegance of oud and amber to the delicate notes of rose and musk, every fragrance is a tribute to the rich olfactory heritage of the region.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://reefperfumes.com'),
('Cristiano Ronaldo', 'Cristiano Ronaldo, the famous footballer, has a brand “CR7” that extends to various products, including footwear, clothing, fragrances, sunglasses and underwear. The CR7 brand is positioned in the premium and luxury fashion segment. All the CR7 shoes will be carefully designed and tested, using the finest available leather and a perfect standard regarding fit and workmanship.', 'Portugal', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Escentric Molecules', 'Escentric Molecules celebrates perfumery as the art of chemistry. The fragrances are presented in binary pairs, each pair explores the qualities of one aroma-molecule in two different ways. The Escentric fragrance focuses on an exceptional aroma-molecule, enhancing its key qualities with other ingredients. The Molecule fragrance takes a minimalist approach, containing only the aroma-molecule, pure and singular. Stripping away the pretension that often surrounds the fragrance world, Escentric Molecules focuses on what is truly exceptional about perfumery, the aroma-molecules that are the perfumer''s palette.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://escentric.com'),
('Baldessarini', 'Baldessarini is a German luxury fashion brand specializing in sophisticated men''s apparel and accessories. Founded in 1993 by Werner Baldessarini, a former Hugo Boss executive, the brand is known for its high-quality materials and impeccable craftsmanship. It caters to a discerning clientele, offering timeless elegance and superior tailoring.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.baldessarini.com'),
('Jean Patou', 'Jean Patou was a French fashion designer who founded his eponymous house in 1914 in Paris. Described as ''the most elegant man in Europe'', Jean Patou was a pioneer and revolutionized fashion in the 1920s. Introducing the idea of leisure for the first time, he wanted to free women from the restrictive clothing imposed on them up until then. He was the first one to launch a sport line, making tennis player Suzanne Lenglen his first muse, and designed garments that would accommodate the daily lifestyles of women.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.patou.com'),
('Amouroud', 'The AMOUROUD fragrances are born out of Perfumer''s Workshop legacy. They are the evolution of the custom blending concept that won Perfumer''s Workshop recognition for its visionary ideas. These are extremely refined, perfectly proportioned and beautifully balanced perfumes. Shimmering and dreamy, provocative and dark, both light and warm, AMOUROUD is a Collection of olfactory memories, stories real and imaginary, translated with wood-notes, flowers, roots, and herbs into perfumes that capture a primal place of serenity, joy, and passion.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Usher', 'Usher Raymond IV, R&B Pop Star, has achieved an incredible success with his fifth album Confession. This album was introduced in 2004, sold so far in 11 million of copies world wide, and is still selling in a million of copies every month. The cooperation with Alicia Keys has brought the beautiful song My Boo that has become a world-wide hit. Now, in 2007, he has launched two fragrances – Usher He and Usher She.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Unknown', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Aramis', 'Aramis was a pioneer in the men''s prestige grooming products and fragrance market. The brand was launched in 1964 by Estee Lauder Companies, it was named for a character in Alexandre Dumas'' beloved classic "The Three Musketeers." The original Aramis fragrance made a splash upon first introduction and continues to attract new devotees with each generation. The scent is a classic masculine mix of woody and spicy notes that fans say never goes out of style.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mandarina Duck', 'Mandarina Duck is an Italian fashion brand, most commonly associated with designer luggage and travel accessories but which has also released sunglasses, fragrances, watches, perfumes and, in 2007, a mobile phone. Mandarina Duck was founded in 1977. The company name and logo come from the Mandarin duck (Aix galericulata), a species that inhabits rivers and lakes in East Asia.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mandarinaduck.com'),
('Sainte Valere', NULL, 'K.S.A', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Roger & Gallet', 'Roger & Gallet is a French perfume house founded by Charles Armand Roger and Charles Martial Gallet in 1862. The history of this house actually begins many years before the company was founded. In 1806, Jean Marie Farina established a successful business supplying Eau de Cologne, based on the historic original formula created by his great grand-uncle, Johann Maria Farina, in the 1700''s. Jean Marie Farina sold the catalog of his company to Roger and Gallet in 1862.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://en.roger-gallet.com'),
('Maurer & Wirtz', 'Maurer & Wirtz is a German manufacturer of personal care products and perfumes. The house was founded in 1854 by Michael Mäurer and his stepson, Andreas Wirtz, when they decided to start production of soap in the small town of Stolberg near Aachen, Germany. This company has stayed in the family for five generations so far. They represent recognizable fragrances and body care products.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.m-w.de/en'),
('Jil Sander', 'Jil Sander is a German fashion house founded in 1968 by Jil Sander. The brand is known for its minimalist design, sophisticated simplicity, modernity, elegance and timelessness. Jil Sander focuses on innovative collections without compromising its aesthetic. The brand is now based in Milan, Italy, under the creative direction of Simone Bellotti since March 2025.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://jilsander.com'),
('Jacques Bogart', 'Jacques Bogart is a French brand specializing in fragrances for men. Since its creation in 1975, it has asserted its roots in a masculine and virile universe. Jacques Bogart fragrances leave a powerful olfactory imprint and an originality that transcends fashion. The Jacques Bogart Group is an independent French family-owned group specializing in the design, production and distribution of perfumes and cosmetics.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Sergio Tacchini', 'Sergio Tacchini is an Italian sportswear and fashion designer. In 1966, Sergio Tacchini founded Sandys S.p.A. (renamed Sergio Tacchini a few years later) with the goal to experiment with fabrics and colours for sportswear. The brand gained worldwide recognition by infusing color into an otherwise all-white sport while partnering with the world''s top tennis athletes.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Sean John', 'Sean John is a fashion lifestyle company created by Sean "Diddy" Combs. The line made its fashion debut with a men''s sportswear collection for the spring 1998 season. Sean John blends luxury taste with urban edge. The Sean John man is confident, creative, and ready to make a statement. The brand offers clothing, footwear, fragrances, and accessories.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Saint Hilaire', 'Saint Hilaire is a French brand that produces fragrances. The brand is known for its aromatic blends, often combining citrus, spices, and woody notes. Saint Hilaire fragrances aim to reflect inner soul and express strength.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mustang', 'Mustang is a German brand that specializes in jeans and clothing. Founded in 1932 as L. Hermann Kleiderfabrik, Mustang became a pioneer in denim manufacturing in Europe. The brand name Mustang is registered and internationally patented and symbolizes the freedom of the Wild West. Another brand named Mustang can be found based in Elche, Spain which specializes in footwear.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Kiton', 'Kiton is an Italian luxury fashion house founded by Ciro Paone in Arzano, Naples, in 1968. The brand is known for exquisite craftsmanship and quality, specializing in high-end men''s and women''s tailoring, ready-to-wear, and accessories. Kiton is renowned for its handmade suits, which are considered among the world''s finest.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.kiton.com'),
('Gilles Cantuel', 'Gilles Cantuel is a French brand that produces perfumes and colognes. The brand offers a variety of fragrances, often blending refreshing citrus and mint with aromatic heart notes and warm, woody bases.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Brioni', 'Brioni is an Italian menswear luxury fashion house based in Rome, founded in 1945. They specialize in sartorial ready-to-wear, leather goods, shoes, eyewear, and fragrance, and provides a tailor-made service. Brioni is known for its exceptional craftsmanship and exquisite tailoring, combining traditional methods with modern style solutions.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.brioni.com'),
('Victorinox Swiss Army', 'Victorinox is a knife manufacturer and watchmaker based in Ibach, Switzerland, founded in 1884 by Karl Elsener. It is known for its Swiss Army knives. The Swiss Army Knife began its worldwide triumphal march after the Second World War through sales in the PX shops on US Army bases. Victorinox also licenses its logo for watches, apparel, and travel gear.', 'Switzerland', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.victorinox.com'),
('Robert Graham', 'Founded in 2001, Robert Graham is a New York-based luxury men''s fashion brand known for its unique prints and textiles. The brand offers menswear, including sport shirts, coats, denim, footwear, outerwear, loungewear, accessories, and leather goods. They also have a womenswear collection with tops, dresses, jackets, and pants. Robert Graham embodies luxury with detailed designs, mixed media fabrics, rich trims, and embroideries, embedding "knowledge, wisdom and truth" throughout each piece.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.robertgraham.us'),
('Reminiscence', 'Reminiscence is a French jewelry and perfume house established in 1970 by Zoe Coste and Nino Amaddeo. Beginning with a boutique in Juan-les-Pins on the Côte d''Azur, the company offers colorful costume and silver jewelry. They recognized the significance of fragrance and launched their initial perfumes Patchouli, Ambre, and Musc the same year.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Faconnable', 'Faconnable is a high-end clothing brand for men and women founded in Nice, France, in 1950 by Jean Goldberg, a master tailor. Façonnable embodies French Riviera elegance and timeless sophistication. The brand began as a tailor shop frequented by Hollywood stars for bespoke tuxedos and gowns for the Cannes Film Festival.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.faconnable.com/en_eu/home'),
('Halston', 'Halston (Roy Halston Frowick) was an iconic American fashion designer of the 1970s, born in Iowa in 1932. Initially known for hats, Halston gained fame for his dresses, which became a staple in American discos. The brand is known for its elegant fashions with a streamlined look. He created strong codes that are quintessential to the brand to this day, as a new team of innovators. Today HALSTON is a luxury lifestyle brand – mixing legacy codes with a modern edge to create an effortless collection of women''s ready-to-wear and dresses.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAJsGBVSnD6O8Hikab2XxYsLJx0TagMUZs2g0sA52K-Y6XtFTsaTVCXs6szCiDyl562HdTrCSgB6ueT1g_dySTDiHM-2VOVblq3EHsjr8ZI='),
('Fly Falcon', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Eutopie', 'Eutopie is a French fragrance brand established by Elodie Pollet in 2011. Inspired by the concept of ''utopia'', the brand creates fragrances that encapsulate aromatic memories of different cultures around the world, interpreted with a French touch. Eutopie fragrances are made in collaboration with talented perfumers, using high-quality ingredients and unconventional compositions.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('K.Arthur', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Scent Zone', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Shakespeare Perfume', 'Shakespeare Perfumes is inspired by William Shakespeare, capturing the range of human emotion and conflict in its scents. ', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Porsche', 'Porsche, officially Dr. Ing. h.c. F. Porsche AG, is a German automobile manufacturer specializing in luxury, high-performance sports cars, SUVs, and sedans. Founded by Ferdinand Porsche in 1931, the company is known for its iconic designs, racing heritage, and engineering. Porsche''s current lineup includes the 718, 911, Panamera, Macan, Cayenne, and Taycan.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.porsche.com'),
('Parfums RP', 'RP Parfums Paris is a new perfume brand positioned as a truly French brand. The ideas behind the brand are the lightness of life and Parisian chic, but they actually created fragrances of rather Italian richness and sweetness.  RP Parfums Paris presents not only perfumes but also home fragrances.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Orlov', 'ORLOV IS A JEWELRY BRAND WITH THE SPIRIT OF MONTE CARLO, FOUNDED IN 2011 BY ANGELA AND CHRISTIAN ORLOV. THERE IS A NATIVE OPULENCE AND A BOLD CONFIDENCE THAT CHARACTERISES ALL ORLOV JEWELRY DESIGNS - LINKED TO THE MAJESTIC INSPIRATION OF THE CROCODILE, THE SPIRIT OF MONTE CARLO AND THE SPECTACULAR GEMSTONES AND DIAMONDS THEY INCORPORATE. THESE ARE DRAMATIC JEWELS THAT EMBODY A GRANDEUR THAT NEEDS TO BE SEEN, HELD AND WORN, TO BE BELIEVED. PASSION AND ATTENTION TO DETAIL CONNECTS THE ENTIRE PROCESS, FROM SOURCING TO THE IN-HOUSE DESIGN AND FINALY TO OUR ATELIER IN VALENZA, ITALY.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAK1yIizqo7dBunYOBLYzt1iFTnWSQvTd-riXuFFjBzLip-OzrJKRfFGgy2V6HvYrEbldeDhSl0OMJE-7xtp8uvFKt03-gXElH6GiWbyWZqaZLiMKYNg-zX2'),
('Marbert', 'The traditional German brand Marbert is offering quality skincare since 1936. Marbert is considered one of the leading cosmetic brands in Europe and its products are consistently made in Germany. Technical know-how, years of experience and unique knowledge of skin properties make Marbert unique.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqALGhg0vs5bkk1iC4E3NzXArme7OFJSYtjLsKlEFl1BqtZuTJeB3zBvW8cLeecOFQRWOJx6P-bRyz8yIVJMZ33Ptr3eLwhj48upwzZKK1TmRgGdao0QlvVPII6yvPopSqTdWBMgJucjX1ZZTWVXp'),
('Karen Low', 'Karen Low is one of several brands that Geparlys markets. The Karen Low scents all came in large fancy bottles, with very elaborate boxes, and were very low-priced. I thought some of them smelled okay but were nothing original or special. Her fragrant creations are works of art that transport the senses to a world of dreams. From delicate floral notes to woody, gourmand accords, each Karen Low fragrance is an olfactory symphony that seduces and captivates.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://www.geparlys.com/en/geparlys_accueil.htm'),
('John Varvatos', 'John Varvatos is an international American luxury men''s lifestyle brand founded by John Varvatos, that designs, manufactures, and retails high-end fashion, using rock aesthetics as the foundation of the brand''s designs. The fashion collection is distributed in 10 freestanding John Varvatos boutiques across the US, as well as in high-end department stores throughout the world.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.johnvarvatos.com'),
('Tom Daxon', 'In contrast to some of the heritage brands with centuries of scent behind them, Tom Daxon is only in its 10th year, but is already a firm favourite in the luxury fragrance sector. ', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAIuZi5P9LYg1xvbs6MdFgWjI-iLEIPGK_AKc8JKFoC8f3Nc6_oAxyAd6DX-vuzb5yQcm-k5BoVGW_Ba0Otwl6Kn17R7TIa3269Wnw4qZvjybMX7-5Xy0887LDUe2fnBhIaL4HXwN5H5bpsscpjoglE='),
('Etat Libre d''Orange', 'Etat Libre d''Orange is a declaration of independence. Perfumes for life and love and making love. When Etienne de Swardt created his house of perfume in 2006, it was only right and natural for him to give it this name, to honor his birthplace and what it represents. Welcome to État Libre d''Orange, where audacity and freedom merge to create unique perfumes that defy conventions and celebrate individuality.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Carner Barcelona', 'Carner Barcelona transmits through its perfumes the contemporary and vibrant spirit of Barcelona; its Mediterranean soul, its architecture, culture, history and its effortless way of living. Carner Barcelona is a lifestyle perfume brand that brings the contemporary spirit of Barcelona to life. Each fragrance is designed to express the brand''s Mediterranean soul; its architecture, culture and the unique way in which history merges with the effortless lifestyle and the vitality of its people.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAJvYkgEhbojKn0HWvyfHczmhAdtFenL5jfNmVzT9l_mgVSGLEUTxs5ySeUAWtmlghghqzWGcpC-ByARjVylqSHumMaUN1RzXiZvpqBQFolH8VTptyJRXgJRIAzq2_ff2omiYBt1cCSLLRyVc_rPedsg7wIk2T9A'),
('Ramon Blazar', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('LPDO Perfume', 'LPDO is an Italian brand founded in 2016 and started selling in Europe in 2017.  It is not just about creating fragrances, but also conveying an emotion through a unique, firm and nonconformist packaging. The traditional bottle transforms into an object of design that can be flaunted like a gem. The high concentration of the best raw materials makes the LPDO fragrances to be persistent and strong, creating a collection of scents designed to satisfy the most demanding noses.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAI95CAYfylfQf-2oRtukx_tnmwelbYuhDprZcSA9VqHOyQEGOprno42USNlKZgCek4NMrCE5WZG6vij2NXSh5Kp6g26MTpr2_7kHRvfYtf_CDvAsB4buY5zJ6_Un6oPysAzFvHhGBki3arR'),
('Boulevard Paris', 'Boulevard Paris Perfumes embody the timeless elegance and sophistication of Parisian style, transporting you to the streets of the City of Light with every spritz. Each fragrance is carefully crafted using the finest ingredients and the expertise of master perfumers, ensuring unparalleled quality and refinement. From classic floral bouquets to modern, contemporary blends, Boulevard Paris offers a diverse range of scents that cater to every taste and occasion. Princesse Parfums collaborates with the best perfumers and noses in the profession in order to draw the best notes from the heart of essences. olfactory which make up its perfumes.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAIu1ZUm34k4j2DCKMFQtWRR6eGF7HMOYbKuT0hG9MvGqNSvkpDGqDABuTmpr5UIJaR3WwRJsj2gjZckQImDmTY-tC1mFmTGBXL4AtZqWJVfELdvNdmi0OYWU-Ed'),
('Pascal Morabito', 'Pascal Morabito is a distinguished French designer and perfumer renowned for his creativity and innovation. With a passion for art and aesthetics, Morabito founded his eponymous brand in 1967, delving into various fields of design, including fashion, jewelry, and fragrance. Reconciling Trade and creation, science and poetry, true humanist artisan, each Pascal Morabito''s jewel is a message, a communication tool, a synthesis. The hotel line perfectly reflects the spirit of Pascal Morabito''s creations, a subtle blend of luxury, refinement and sobriety.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Attar Collection', 'Attar Collection, founded in 2015 and based in Dubai (UAE), is a niche, luxury perfume house offering the richest quality of perfumes and natural oils presented in an exclusive design and a modern elegant image. It has a one-of-a-kind collection of oriental and western fragrances inspired by Arabic culture and heritage. All products are limited editions of the work of famous designers and a perfumer who prefers to remain anonymous. In the process of creating new fragrances Attar Collection always follows the same principle of using raw highest quality materials.', 'Uae', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqALvLt9a72ATZnyKhS4IXoRLdVUnMUM1_ZmkjMXlxSJjKMFC7a2Xd-qf8auRhT3_UJqXMffaNrAuEH4rC2it4wnMgn3aCJD1qcT4i8EQfCuzvJEKgBvgiMb-Lxw1vgcAyeoA3KM='),
('Ard Al Khaleej', 'Ard Al Khaleej is a brand renowned for capturing the rich, luxurious essence of Arabian perfumes. With its deep roots in Middle Eastern culture, Ard Al Khaleej offers a stunning array of fragrances that blend traditional oriental notes with modern twists. Each perfume from Ard Al Khaleej is a reflection of the Middle East''s fragrant history. From rich ouds to sweet ambers and spicy musks, these perfumes are crafted with ingredients that evoke the luxurious lifestyle of the Arabian world.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Chaugan', 'Chaugan is an exquisite perfume brand known for its unique and luxurious fragrances. Thousands of years ago, in the East, there was a noble athlete and warrior—the Chaugan, whose history in Persia was written probably during the reign of King Darius (522-486 BC). The man became a popular entertainment and sports king admired by all and interest in him has not faded over the centuries. The palaces'' architecture, chiseled like jewels, are scented with delicate scents, their curtains swaying to the rhythm of a hot wind while one lounges on a luxurious silk carpet.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAJITKZhfztTlbek1o6kOBpgnRAHZ3PvY1ZjlADBajAfPyaS2s75vmhpp5fZ_mL_2JzVgCxcJQTypLZfGG9miMLpJZtuI1z2UqaRuoRzEbdp5KDhAm4wbacCqn3HKjJxIyB0b37KKUPfWiZJjPc='),
('Acqua Di Monaco', 'Acqua De Monaco is a luxury fragrance brand founded in Monaco, known for its exquisite, fresh scents inspired by the Mediterranean. Aqua di Monaco is a range of perfumes designed for the person who seeks success, ambition, and honor. ACQUA DI MONACO is mix of many flowers; Lily of Valley, Rose, Violet and Tuberose, with middle notes of sandalwood and cedarwood and finishing with Amber and Musk.', 'Monaco', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('David Kasab', 'David Kasab is a modern brand that originated in the Kingdom of Saudi Arabia and offers a range of perfumes. It comes from the style of old Europe with its luxury and charm. A new adventure of lemon and bergamot fragrances that express the events of a life full of excitement.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Jul Et Mad', 'Jul et Mad Paris is a French fragrance house that was founded in 2012 by Julien Blanchard and Madalina Stoica-Blanchard. The luxurious fragrance creations of "Jul et Mad" reflect the close bond between the two founders, their passions, and their love for each other. Since its launch in 2012, the Art of Perfumery became the scene where a beautiful and extraordinary Histoire d''Amour is revealed: the very true story of the two founders, Julien (JUL) and Madalina (MAD).', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAIVuNqXh0m9i5KMPvxRyTgL258BVdLQNGQIfkSF0mTin3csmz3JOP0K6gRA2ffWxdxGzfQuJAKDOCleBmGWzc953evSVqTOXmvsb5gvy7ioX_0bQu8dF52u4XNNRsWaE669i6EgREnZsCJFYbepz31Kaklbtwc='),
('ABAQ', 'Abaq Perfume by Al Majed Oud, A Velvety Sensation of Enchanting Aromas The fragrance is the finest collection of carefully selected woody fragrances, which is elevated by the freshness of Bergamot that smoothly blends with the purity of musk. ABAQ Company for perfumes touched the hearts of customers in Dubai to complete the luxurious mosaic of beauty in the world of perfume on the approach of our ancestors and fathers. We have gathered our 15-years of experiences to offer you in a new way', 'Uae', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://vertexaisearch.cloud.google.com/grounding-api-redirect/AWQVqAIm28Ldpvws32EtmxSBjs7V1mgEc5ydHn4Ff4MU2zWeDaBMwVRO_AxMaukTgRMTkbrNPcz-_JVr3sHMbR46Ntx0KZ7h3syVcZrRfkSfvbQ-'),
