('Wadi Halfa', 'Wadi Halfa is the first Arab store offering charcoal, firewood, and a wide range of incense supplies with high quality and professionalism.', 'South Africa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Aradous Perfumes', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Brands Me', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Dize Home', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Keba Perfumes', 'Keba Perfumes is a Saudi house for the manufacture of distinctive perfumes that suit all tastes. The name Quba means incense stick. It is distinguished by quality and extreme care in the manufacture of its perfumes, as it extracts perfume scents from the finest natural ingredients with unique scents.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mabkharah', 'Mabkharah offers Arabian Bakhoor crafted from agarwood, promising a long-lasting, mesmerizing aroma.', 'United Arab Emirates', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Banafa For Oud', 'Banafa for Oud is a leading brand in the manufactury of unique and distinctive fragrances with a touch of luxury. It''s specialized in producing the best oud, incense, cosmetic products, fragrant oil as well as Arabian and European fragrances. It has wholesale and retail branches in Saudi Arabia, Dubai, Yemen, Bahrain and other countries. Banafa for Oud was established in 1987 with a factory in the industrial zone in Jeddah, designed with the latest international standards of manufactury and production.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Arabian Oud', 'Arabian Oud is a prestigious fragrance brand established in 1982 in Riyadh, Saudi Arabia. Originating from the traditional Souk al-Azal marketplace, it has grown significantly over the decades, becoming one of the largest fragrance houses in the Middle East with a global footprint that includes over 1200 stores in 37 countries. The brand specializes in luxury scents, particularly those featuring Oud, a prized aromatic resin central to Middle Eastern perfumery. With a diverse range exceeding 400 products, Arabian Oud offers fragrances tailored for men, women, and unisex use.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://shop.arabianoud.com/'),
('Oud Lover', 'Oud Lover is known for home fresheners and perfumes with natural oud notes and a blend of sandalwood, saffron, and musk, providing freshness and psychological comfort.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Batalat', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('NOOR', 'NOOR is a brand that originated in 1985 with the launch of Noor Sunflower oil. It was the first brand in the Middle East to introduce Trans Fat Free Cooking oils. Noor is passionate about helping families enjoy healthy and tasty meals and is one of IFFCO''s flagship brands with strong brand equity among households. Alternatively, Noor Arfa is an exclusive Batik company that has been operating for more than 39 years in Malaysia. It is a pioneer of the well-known batik industry in Malaysia and has been operating in Kuala Terengganu since 1980.', 'United Arab Emirates (For Noor Food Products) / Malaysia (For Noor Arfa Batik)', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Layl', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Al Khuraiji', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Two Mark', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Alsalman Group For Oud', 'Alsalman Group is a Saudi company specialized in producing different kinds of saffron, natural and artificial oud, in addition to fragrances and incense. It has an expertise of over 60 years, offering products with high-quality and low prices.', 'Saudi Arabia', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Lava Moments', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('EstÃƒÂ©e Lauder', 'Estée Lauder is a global cosmetics brand specializing in skincare, fragrance, makeup, and hair products. Founded in 1946 by Estée Lauder in New York City, it owns several popular brands, including MAC Cosmetics, Clinique, and Jo Malone. Estée Lauder is the flagship brand of The Estée Lauder Companies Inc.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://elcompanies.com'),
('Miu Miu', 'Miu Miu is an Italian high fashion women''s clothing and accessory brand and a fully owned subsidiary of Prada. It is headed by Miuccia Prada and headquartered in Milan, Italy. Miu Miu was born in 1993 from the independent and unconventional spirit of Miuccia Prada. The brand is focused on a younger audience and is also popular for its footwear collections.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.miumiu.com'),
('Jovan', 'Jōvan is a fragrance brand with a longstanding history. Since 1972, Jōvan has been a fragrance leader. Its Musk fragrance continues to be a best-selling Musk brand in broad distribution. Jōvan''s early marketing campaigns became industry benchmarks and, during the Rolling Stones'' 1981 "Tattoo You" Tour, it was the first-ever fragrance to sponsor a rock band. Today, Jōvan''s appeal can be attributed to its abiding sensuality, and down-to-earth values.', 'Usa', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Mugler Les Exceptions', 'Thierry Mugler is a French fashion designer and photographer known for his 1980s power fashions and widely credited with introducing a new fragrance trend or category—gourmand—in the 1990s. The bottles, designed specifically for the Les Exceptions collection, are universal, unisex in their structure, and of clean, luxurious and simplified lines. They are ornamented in the spirit of Art Deco, using a wide strap of silvered metal, a material that is also used for the cap. The collection is available in 80 ml bottles.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.mugler.com'),
('Tory Burch', 'Tory Burch LLC is a luxury women''s fashion label based in Manhattan, New York, founded by Tory Burch in 2004. The brand is known for its ready-to-wear, shoes, handbags, accessories, watches, home decor, and fragrance and beauty collection. Tory Burch began her fashion label in February 2004, launching it with a retail store in Manhattan''s Nolita district.', 'United States', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://toryburch.com'),
('Volnay', 'Volnay is a small wine appellation located in the Côte de Beaune region of Burgundy, France. The history of winemaking in Volnay dates back to the Roman era, and the area has been producing high-quality wines for centuries. The primary grape variety grown in Volnay is Pinot Noir, which is known for its delicate aromas and flavors of red fruit, earth, and spice.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Acqua Di Sardegna', 'Acqua di Sardegna is a brand inspired by the island of Sardinia, embodying beauty and Italian excellence. Their collection includes exclusive lines of perfumes that capture the essence of the island, with a focus on Mediterranean citrus fruits and aromatic herbs.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.acquadisardegna.com'),
('Fan di Fendi', 'Fan di Fendi is a fragrance line by the Italian luxury fashion house Fendi. Fendi was founded in Rome in 1925 by Adele and Edoardo Fendi and is known for its fur, leather goods, and accessories. Fan di Fendi is a tribute to the fascinating Fendi universe and captures the essence and DNA of the brand.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.fendi.com'),
('Santi Burgas', 'Santi Burgas is an avant-garde and alternative brand of author perfumes born in 2008 in the heart of the Empordà region. The brand''s spirit is to offer design and innovation, creating sophisticated Eau de Parfum fragrances with high-quality ingredients. The unique and unexpected formulas are born drop by drop, in his "ant colony”, impregnated with fine aromas, and then produced in Barcelona with high quality essences.', 'Spain', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.santiburgas.com'),
('Masque Milano', 'Masque Milano is an Italian fragrance house founded by Alessandro Brun and Riccardo Tedeschi in Milan in 2010. The brand''s fragrance collection has a strong identity: each one represents a moment, a place visited, an emotion, or a dream. Masque Milano strives to value the Italian artisanal heritage through high-quality fragrances.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Laurent Mazzone', 'Laurent Mazzone Parfums is a niche line of scented candles and fragrances founded by Laurent Mazzone. Passionate about perfumes since the tender age of 12, Laurent Mazzone founded his perfume house in 2010 with the aim of best expressing his creativity and artistic taste. The brand focuses on oriental notes, rich in color, sketching opulent and sophisticated scents, charged with undeniable sensuality.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.lmparfums.com'),
('CnR Create', 'CnR Create is a perfume brand born in Vienna. Every perfume from the collection of 12 perfumes (It''s Me) is devoted to its star sign. Robert Boehm is our Astrology Expert. Designer CnR Create has 36 perfumes in our fragrance base. CnR Create is a new fragrance brand. The earliest edition was created in 2008 and the newest is from 2011. The nose who worked on the fragrances is Olivier Funel.', 'Austria', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Atelier Flou', 'Atelier Flou is a French perfume brand that includes 4 fragrances for men and 4 for women. The brand was established in 2014. The brand''s new bottle design was inspired by 19th-century inkwells, with gold or silver latticework encasing the bottle.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Boadicea', 'Boadicea the Victorious is an independent British fragrance brand that takes inspiration from a defining moment in history. They have created a range of gender-neutral perfumes that are quintessentially British and of incomparable quality. Each iconic bottle has been hand-crafted by some of Britain''s finest artisans and illuminates how the brand champions British heritage and values.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.boadiceathevictorious.com'),
('Amado', 'Amado is a newer fragrance brand from France, with its earliest edition created in 2014. They offer a range of perfumes and have collaborated with perfumers like Christian Provenzano, Ian Watt and Anna Chiara di Trolio. Aside from fragrances, ''Amado'' is also used as the brand name for rugs and wall sconces.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Lola Mood', 'Lola Mood Parfums is a new fragrance brand from Italy that launched a collection of four fragrances in 2013 inspired by the red carpet and celebrities. Their ATTITUDE: RED CARPET collection combines glitz and glamor with interesting compositions in attractive bottles.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('D''Orsay', 'D''ORSAY is an aristocratic perfume line from France, founded in 1908 with the goal to preserve the Count''s perfume heritage and develop an aristocratic luxury perfume house on its basis. Their philosophy is based on quality, understatement, character, seduction, praise, creativity, and originality. They have a long tradition and heritage, using ingredients of the highest quality. In February 2007 the house was acquired by Marie Huet.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://maison-dor say.com/en/'),
('A Lab on Fire', 'A Lab on Fire, also known as WHAT WE DO IS SECRET® in the U.S., creates fragrances in collaboration with perfumers. Their fragrances evoke meaningful instants spent embraced by the beauty of nature. The brand combines unique formulas with patented technology - Inoscent™.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://wwd.is/'),
('Majda Bekkali', 'Majda Bekkali, born into a noble family of Fes, Morocco, established her own perfume house in 2009 driven by a passion for scents and raw materials. The brand''s perfumes float on new lands of promise, at the crossroads of irreverent utopias and deep-rooted cultures. Their fragrances are essentially works of art waiting to be discovered.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.majdabekkali.com/'),
('Sospiro', 'Sospiro Perfumes, inspired by the sophistication and beauty of classical music, is known for fragrances that celebrate the voluptuousness and splendor of perfumes crafted by a gracious harmony of rare and precious notes. Their perfumes are inspired by the beauty and sophistication of classical music.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://sospirointernational.com/'),
('Clive Christian', 'Clive Christian is a luxury British perfume house, established in 1999 when the designer acquired Crown Perfumery. The brand interprets a refined art, bringing to life a thousand year tradition of fragrances in which luxury, the search for perfection and tradition seem to be limitless. The brand''s predecessor, the Crown Perfumery Company established in 1872, is the only house ever to have been granted permission to use Queen Victoria''s crown on its bottles.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.clivechristian.com'),
('Hermetica', 'Hermetica is a collection of molecular fragrances inspired by the ancient practice of alchemy. Applying these practices to modern day perfume-making, Hermetica is based on the belief that finding the perfect perfume relies on the chemical connection between the molecules within a fragrance and one’s skin. Hermetica Paris was launched in 2018 thanks to the conviction of Clara and John Molloy, willing to initiate a new way to experience and create perfumes.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://hermeticaparis.com/us_en/'),
('Mendittorosa', 'Mendittorosa is an Italian niche perfume house from Rome that debuted at Fragranze with three fragrances: ALFA, OMEGA and ID. Mendittorosa is a ''scent path'' that returns the scent of soul. Each odor has its path, the one chosen by the wearer. Scents of soul and with the soul.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Biehl', 'Founded by Thorsten Biehl in 2006, biehl parfumkunstwerke is an olfactory gallery that offers distinguished perfumers scope for devising some extraordinary creations. Free of any commercial pressures, international fragrance artists create unusual and exclusive scents for the lover and connoisseur of perfume that are being sold in minimalist packaging and limited editions by selected parfumiers.', 'Germany', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Au Pays de la Fleur d''Oranger', 'Au Pays de la Fleur d''Oranger is a family-run company from France, founded in 1998 by Virginie and Antoine Roux. The brand launched their perfume and cosmetics line in 2005/2006. The brand is known for perfumes where orange blossom is king, taking you on an olfactory journey to the heart of the sunny scents of the Côte d''Azur hills. They offer a range of exquisite, genuine Haute de Gamme fragrances that serve as a timeless link between their passionate present and extremely exciting future.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Electimuss', 'Electimuss London is a luxury niche brand inspired by Ancient Rome and the Romans'' obsession with perfume. Electimuss, meaning “to choose the best” in Latin, creates intense and indulgent fragrances with potent combinations, resulting in powerful, long-lasting perfumes with exceptional projection and longevity. They use the finest oils and resins and collaborate with world-class perfumers to craft bold and refined scents that explore power, creativity, and sensuality.', 'London', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Affinessence', 'Affinessence is a niche French brand that creates art perfumes without the typical olfactory pyramid. Founded by Sophie Bruneau, the brand focuses on high-quality, linear fragrances made with rare and precious ingredients. Affinessence perfumes are designed to remain constant on the skin throughout the day, offering a unique and luxurious olfactory signature. Their perfumes do not divide into top, middle, or base notes, ensuring the scent remains consistent. The brand''s name means ''affinity with essence''.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://affinessence.com'),
('Aether', 'ÆTHER, founded by Nicolas Chabot in 2016, creates conceptual fragrances using synthetic molecules to honor the foundations of modern perfumery. Aether perfumes are a tribute to synthetic molecules and the frenzy of chemistry. Each perfume explodes into a singular abstraction, a beautiful stranger, with elementary molecules creating olfactory kamikaze.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Liquides Imaginaires', 'Liquides Imaginaires is a French fragrance house founded by David Frossard and Philippe Di Méo. The brand aims to revive the perfume ceremony and ritual by developing new objects and alternative habits. Their fragrances are designed to be mysterious and enclose the genius of perfume within, like an amphora. Liquides Imaginaires always releases fragrances as a trilogy—a collection of three scents related in theme.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Guru', 'Guru Perfumes is a niche perfumery brand founded in 2015. It is a miracle that such a small crystal enclosure can be a host to such an amplitude of scents that invoke a whole new dimension of spiritual corridors to delve into. Designer Guru Perfumes has 11 perfumes in our fragrance base. Guru Perfumes is a new fragrance brand. The earliest edition was created in 2017 and the newest is from 2019.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Simone Andreoli', 'Simone Andreoli is a luxurious fragrance brand that encapsulates journey experiences, personal memories, and a creative soul expressed through the art of perfume. Each bottle holds a unique sensory experience, like the page of a logbook where words, feelings, and life stories are imprinted. It is an olfactory diary that uses aromatic accords and noble refined ingredients to evoke the emotional aesthetics of travel, transporting the mind to far destinations and remote corners.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Goutal Paris', 'Goutal Paris, formerly Annick Goutal, is a luxury brand synonymous with artisanal perfumery. Since its launch in 1981, the brand has focused on creating beautiful fragrances with meaningful scents, presented in attractive bottles. Annick Goutal, an inspired woman and one of the first female perfumers, created L''Eau d''Hadrien, her first signature perfume, evoking the Tuscan landscapes with a refreshing citrus cocktail tinged with cypress.', 'Paris', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Eisenberg', 'EISENBERG Paris is a French luxury brand founded by José Eisenberg in 2000, encompassing skincare, make-up, sun care, and fragrances for women and men. The brand is known for its high-tech products and the exclusive Trio-Molecular® Formula, combining biotechnology and natural ingredients. Eisenberg aims to provide visible results, elegance, luxury, and timelessness.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Arquiste', 'ARQUISTE Parfumeur is a fragrance collection created by Carlos Huber, an architect specializing in Historic Preservation. The brand transports the wearer to evocative moments in history through meticulously researched fragrances crafted with rare ingredients. Each scent restores the olfactive experience of a particular time and place, allowing both women and men to unlock personal revelations and experience history in an intimate way.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Profumo di Pantelleria', 'Profumi di Pantelleria is an Italian niche perfume brand established in 1997 and dedicated to the Italian black pearl - the Mediterranean island of Pantelleria. The brand captures the flavors and scents of this beautiful land, reflecting its beauty and grandeur in a whole line of fragrances. The perfumes symbolize the coming together of Italian elegance and oriental flair, with the idea of creation coming to a group of faithful habitués to capture the lively memories and intoxicating aromas of the island in a bottle.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('The Harmonist', 'The Harmonist, founded in 2016 by Lola Tillyaeva, is a maison de parfum that combines the craft of haute perfumery with the principles of Feng Shui. The brand''s ethos is rooted in the ancient Chinese philosophy of Feng Shui, viewing the universe as composed of five fundamental elements: Water, Fire, Wood, Metal, and Earth. Each element plays a vital role, and when balanced, leads to harmony and well-being. The Harmonist uses ethically sourced, high-quality ingredients to create fragrances that empower wearers, restoring balance for an elevated perfume experience. The brand aims to enlighten the wearer, revealing and enhancing who you truly are, rather than who you pretend to be.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Ormonde Jayne', 'Ormonde Jayne is a London-based luxury perfume house founded by Linda Pilkington in 2000. The house combines English craftsmanship, the art of French perfumery, and the sensuality and natural harmony of the Orient to create unique perfumes. Ormonde Jayne''s philosophy has always been to return to the glorious “golden age” of perfumery, an elegant era when fragrance creation was a fine art. The perfumes utilize speciality oils not widely used in the perfume industry today and are left to mature, naturally and unhurried. The brand manufactures all products in its own London laboratory.', 'United Kingdom', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://ormondejayne.com'),
('Maison Crivelli', 'Maison Crivelli is a French niche perfume brand created by Thibaud Crivelli in 2018. The brand''s ambition is to surprise and enable a sensorial and personal interpretation of perfume. The origin of each fragrance lies in an unexpected discovery of a fragrance raw material. Maison Crivelli fragrances are crafted in France with integrity and displayed in handmade plastic free boxes. Each bottle reveals an unpolished zamac cap, stamped with the Maison Crivelli monogramme, making each cap unique.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Les Eaux Primordiales', 'Les Eaux Primordiales is a French niche perfume brand built on the foundations of the traditional "Great Perfumery". Created by Arnaud Poulain, in collaboration with Amélie Bourgeois, its mission is to offer timeless, innovative fragrances that redefine contemporary classics with the use and reinvention of sometimes forgotten olfactory families. Arnaud''s inspirations are deeply linked to his personal interests: from contemporary art, music, fashion, literature, even to pop culture. The perfumes are created in the Haut-de-France countryside in northern France.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('B96', 'B96 is a fragrance brand created by people who love what they do, for whom perfumes are an important element of expressing themselves, their feelings and emotions. The beginning of B96 brand is a shy dream of creating something special. The brand hopes to allow you to look through the keyhole to the perfumer laboratory and become a guide through the magical world of perfumery. B96 fragrances were made in collaboration with perfumers Michel Girard, Amandine Galliano and Bertrand Duchaufour.', 'Poland', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Les Parfums De Rosine', 'Les Parfums de Rosine was founded by Paul Poiret in 1911 and named after his own daughter. Marie-Hélène Rogeon revived the house in 1991, born into a family of perfumers. Tired of mainstream and designer offerings, she decided to re-open the house Les Parfums de Rosine in order to create original, unique and beautiful compositions made from natural essences. Her creations center around the scent of roses, and she values not only natural ingredients and the fragrant creations but focuses on beautiful and appealing packaging as well.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Maison Rebatchi', 'Maison Rebatchi is a French niche perfumery brand founded by Mohamed Rebatchi in 2018. Passionate about fragrances and a self-taught perfumer, M. Rebatchi created his brand inspired by his origins from Maghreb, beautiful raw materials and his memories. Maison Rebatchi brings together the world''s most renowned master perfumers and skilled artisans to create luxury niche perfumes and elegant scented candles that redefine high-end French perfumery. Every fragrance is a testament to uncompromising quality, crafted from premium raw materials meticulously selected to ensure rich, long-lasting scent compositions that evolve beautifully over time.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Kemi Blending', 'Kemi Blending Magic is a new perfume brand, founded in Italy, whose perfumes were designed by the skilled master perfumer Chris Morris. The brand believes in the power of personal expression through scent and offers a unique and interactive approach to perfumery. Kemi Blending Magic perfumes are characterized by their innovative and versatile compositions. Each fragrance is a harmonious blend of high-quality ingredients, carefully selected and combined to create a unique olfactory experience.', 'Italy', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Christian Louboutin', 'Established in 1991 by French designer Christian Louboutin, the eponymous brand is celebrated for its iconic red-soled shoes. Louboutin''s groundbreaking design philosophy fuses luxury with audacious style. In 2014, the brand launched a series of nail varnishes and, in 2015, the company expanded its foray into beauty with a lipstick collection. Christian Louboutin make-up brings the designer''s signature high-glamour aesthetic to the realm of beauty. Discover highly pigmented lipsticks, lustrous highlighters and spellbinding eau de parfums.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'http://eu.christianlouboutin.com'),
('Unique Luxury', NULL, NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Dali Haute Parfumerie', 'Dali Haute Parfumerie is a fragrance collection inspired by Salvador Dali''s jewelry line. The fragrances were created by Alberto Morillas, who also created the first Dali perfume dedicated to the artist''s wife, Gala. The brand aims to restore luxury to perfumery, drawing inspiration from Dali''s surrealist art and imagery. The collection include fragrances inspired by pieces like &quot;The Persistence of Memory&quot; and the &quot;Chalice of Life&quot;.', NULL, 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', NULL),
('Juliette Has A Gun', 'Juliette Has A Gun is a fragrance project initiated in 2005 by Romano Ricci, the great-grandson of Nina Ricci. The brand presents a collection of fragrances designed for individuals who want to express themselves, with a provocative, ironic, and impertinent approach. Inspired by Shakespeare''s tragedy, the modern Juliette is armed but equally romantic. Each fragrance tells a story, revealing her world, style, and uniqueness, with a blend of romanticism and modern femininity.', 'France', 'https://img.fragrancex.com/images/l/29/us/0/homeimage_mobile.jpg?v=VVMM9DGZ0GH7QG2', 'https://www.juliettehasagun.com/'),
('Robert Piguet', 'Robert Piguet is a French perfume house founded by couturier Robert Piguet. Piguet met famed perfumer Germaine Cellier in the 1940s and worked with her to create perfumes that suited his elegant and modern post-war fashions. The first scent, Bandit, a leathery chypre launched in 1944, was introduced in conjunction with Piguet''s autumn collection.
INSERT INTO Product (brand_id, product_name, description, volume, price, discount_price, quantity_in_stock, reorder_level, image_url)
VALUES
(32, 'Guerlain Mon Florale', 'Mon Guerlain is an ideal perfume for an inspirational woman. This fragrance was inspired by womenÃ¢â‚¬â„¢s dreams, ambitions and choices. It delivers an elixir for elegance and femininity. The opening is audacious and fresh with lavender and bergamot. Sambac jasmine and vanilla occupy the heart giving the fragrance subtlety. Sandalwood at the dry-down gives the scent a mysterious feel. Mon Guerlain is a soft and calming fragrance that is unique in its breathtaking composition and beautiful bottle. The classical bottle is charming in its own simple design, taut lines and sensual curves.', 100, 2428800.0, 2428800.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/3/3/3346470133990_guerlain_guerlain_mon_florale_edp_100_ml_1.jpg'),
(36, 'Narciso Rodriguez For Him EDP', 'Narciso Rodriguez for Him Eau de Parfum is a Narciso frangrance that''s described as sensual with an intense musk scent with floral notes of iris spiced with pink pepper.', 100, 2035500.0, 2035500.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/g/o/golden_scent_perfume_narciso_rodriguez_perfumes_for_him_for_men_eau_de_perfum.jpg'),
(244, 'Creed Sublime Vanille Les Royales Exclusives', 'This soft oriental scent is suitable for both him and her. Its top notes feature Tahitian vanilla and South American bourbon vanilla, complemented by a heart of Tonka bean. The base has notes of Bergamot, Calabrian lemon and Musk.', 250, 43366500.0, 43366500.0, 0, 0, 'none'),
(73, 'Tous Les Jours Classic', 'Classic 100 ml is an Eau de Parfum For Men and Women from Tous Les Jours that will make everyone sense your unique presence with top notes of Pineapples, Hyacinth that will grab your attention immediately, then the heart notes of Jasmine, Pink Pepper, iris Fbasics that will take control representing the essence of the perfume to leave you in the end with the base notes of Musk, Patchouli, Jasmine, Amber, Vanilla, Vetiver that will linger with you far beyond that.', 100, 1649100.0, 1649100.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/6/2/6287006905582_tous_les_jours_tous_les_jours_-_classic_100_ml_tayamun_1.jpg'),
(318, 'Miu Miu L''eau Bleue Mini Set ', 'It''s a two-piece mini set features EDP (100ml) and EDP (20 ml). A floral fragrance with fresh scent of the spring awakening. The composition has lily of the valley notes in the top, followed by a heart of white flowers then musk in the base, providing a scent devoted to the woman who revels in her contradictions.', 20, 3622500.0, 3622500.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/small_image/750x750/9df78eab33525d08d6e5fb8d27136e95/3/6/3614227190047-miu-miu-miu-miu-l_eau-bleue-_w_-edp-100-ml-_-20-ml-travel-gift-set-2-piece.jpg'),
(156, 'Victoria''s Secret Pink Tropic Palm Body Mist ', 'Enjoy a new and exciting adventure through this refreshing and lively coastal journey.
INSERT INTO Product (brand_id, product_name, description, volume, price, discount_price, quantity_in_stock, reorder_level, image_url)
VALUES
(51, 'Al Dakheel Oud Al', 'Touches of aromatic delicacy fill your home with an oriental smell that stays for long hours without fading. The pretty maamoul is the secret of your home''s attractiveness withthe presence all your friends on happy days', 100, 993600.0, 993600.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/small_image/750x750/9df78eab33525d08d6e5fb8d27136e95/6/2/6281150700048-al-dakheel-for-oud-al-ma_moul-al-fakhir.png'),
(326, 'Masque Milano Dolceacqua Le Donne di Masque', 'On a nice day, at 7 am, the sun rises, and the traffic is light in Italy. A charming woman takes you on a picnic with the beautiful breeze flirting with her dress. Here you can see the colorful garden with a scent of floral and marine magic blend in the air. You fix your eyes upon her, open the rum bottle, and lean towards her to pour some happiness into her glass. You just stop pouring your drink while feeling astonished by her bewitching look and dazzling perfume. She smells sweet and mellow and is so much in line with the gardenâ€™s flowers and the scrumptious fruits with a favorable hint of vanilla and cedarwood Virginia at the base. She is capable of stealing all the lights, thanks to Masque Milano Dolceacqua fragrance.', 50, 3967500.0, 3967500.0, 0, 0, 'none'),
(73, 'Tous Les Jours Body Spray Day 323', 'Day 323 Body Mist has a rose scent for lasting fresh sense. Its components are suitable for big customer segments for all times. It contains water notes, lemon, rose, sugar, rice, vanilla, and musk', 250, 338100.0, 338100.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/6/2/6287006900327_tous_les_jours_tous_les_jours_-_body_spray_day_323_tayamun_1.jpg'),
(40, 'Tom Ford White Patchouli', 'Tom Ford White Patchouli the floral scent for women. A calm, lovely and very wearable. It''s elegant enough for evening wear and casual enough for day wear. Perfect blend for every day!', 50, 5513100.0, 5513100.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/g/o/golden_scent_perfume_tom_ford_perfumes_white_patchouli_for_women_eau_de_perfum.jpg'),
(249, 'Cristiano Ronaldo Legacy Private Edition EDP', 'The most masculine fragrance designed with a glowing and evocative scent
INSERT INTO Product (brand_id, product_name, description, volume, price, discount_price, quantity_in_stock, reorder_level, image_url)
VALUES
(73, 'Tous Les Jours Perfume Day 354', 'This spicy woody fragrance keeps you chic and attractive as you seek. Notes of citrus are followed by jasmine in the heart and pine in the base, offering you a unique scent that adds to your charm and inspire everyone there, thanks to the long-lasting effect.', 55, 821100.0, 821100.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/2/0/2000354-tous-les-jours-tous-les-jours-perfume-day-354-1.png'),
(44, 'Bvlgari Omnia Mini Set for Women ', 'This three- piece set from Bvlgari is designed for the modern woman who leaves her signatures wherever she goes. Pink Sapphire is a floral fragrance that fills you with energy as it reminds you to run, jump and dance with notes of frangipani and musk. Amethyste is inspired by the shades of purple for the romantic woman with amazing blend of heliotrope and pink grapefruit. Crystalline is a floral aquatic fragrance inspired by the perfection of crystal. It has a delicate composition with notes of lotus blossom and bamboo.', 5, 1531800.0, 1531800.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/small_image/750x750/9df78eab33525d08d6e5fb8d27136e95/7/8/783320405624_bvlgari_bvlgari_omnia_w_edt_3_x_5_ml_pink_sapphire_omnia_amethyste_crystalline_mini_set_gs-dmm_cross_dock_1.jpg'),
(368, 'Olibere Il Mio Segreto EDP', 'A distinctive fragrance, perfect for both men and women.
INSERT INTO Product (brand_id, product_name, description, volume, price, discount_price, quantity_in_stock, reorder_level, image_url)
VALUES
(116, 'Kholasaat Gold', 'This oriental fragrance is full of strength and vitality, with its special blend of leather and the delicate aromas of jasmine velvet. It''s the perfect scent for lovers of leather, who can wear it on the everyday life as well as for the evening.', 100, 2594400.0, 2594400.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/g/o/golden_scent_perfume_kholasaat_perfumes_gold_for_unisex_eau_de_perfum_6287003650065.jpg'),
(250, 'Escentric Molecules Escentric 01', 'If youâ€™re a fan of unisex, remarkable scents â€“ as opposed to rich, sugared floral onesâ€“ we suggest making Escentric 01 your olfactory perfume. Not just an unbelievable stroke of perfumery, itâ€™s also incredibly wearable. It''s a fragrance you can wear it like a precise piece of jewelry â€“ to add a certain attraction without being tacky or haughty.', 100, 5223300.0, 5223300.0, 0, 0, 'none'),
(11, 'Mont Blanc Presence', 'A strong and attractive fragrance with a complete blend of clary sage, cardamom, and grapefruit. It has a more striking and captivating fragrance with a fresh top touch to it. A masculine fragrance for the confident, courageous man.', 75, 1152300.0, 1152300.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/image/9df78eab33525d08d6e5fb8d27136e95/g/o/golden_scent_perfume_mont_blanc_perfumes_presence_for_men_eau_de_toilette_3386460028325.jpg'),
(219, 'Giorgio Royal Classic EDP', 'A classic luxurious fragrance designed for men with high taste.
