-- 5. Insert data into RolePermission table

-- Admin role permissions (role_id = 1)
-- Admin has all permissions
SELECT 1, permission_id FROM Permission;

-- Manager role permissions (role_id = 2)
-- Managers have broad access but with some limitations
SELECT 2, permission_id FROM Permission
WHERE permission_name IN (
    -- Employee Management (Cannot delete)
    'employee.view', 'employee.create', 'employee.edit', 'employee.view_sensitive',

    -- Role Management (All)
    'role.view', 'role.create', 'role.edit', 'role.assign', 'role.delete',

    -- Permission Management (All)
    'permission.view', 'permission.assign',

    -- Material Management (All)
    'material.view', 'material.create', 'material.edit', 'material.import',
    'material.export', 'material.adjust', 'material.delete',

    -- Material Transaction (Cannot manage)
    'material_transaction.view',

    -- Brand Management (All)
    'brand.view', 'brand.create', 'brand.edit', 'brand.delete',

    -- Product Management (All)
    'product.view', 'product.create', 'product.edit', 'product.details.manage', 'product.delete',

    -- Inventory Management (All)
    'inventory.view', 'inventory.import', 'inventory.export', 'inventory.adjust',
    'inventory.sell', 'inventory.combine',

    -- Inventory Transaction (Cannot manage)
    'inventory_transaction.view',

    -- Promotion Management (Cannot delete)
    'promotion.view', 'promotion.create', 'promotion.edit', 'promotion.assign',

    -- Customer Management (Cannot delete)
    'customer.view', 'customer.create', 'customer.edit', 'customer.rating', 'customer.view_sensitive',

    -- Cart Management (View only)
    'cart.view',

    -- Order Management (Cannot delete)
    'order.view', 'order.create', 'order.edit', 'order.process',

    -- Payment Management (Cannot delete)
    'payment.view', 'payment.create', 'payment.edit', 'payment.process',

    -- Shipment Management (Cannot delete)
    'shipment.view', 'shipment.create', 'shipment.edit', 'shipment.track',

    -- Conversation Management (Cannot delete)
    'conversation.view', 'conversation.create', 'conversation.respond', 'conversation.close', 'conversation.rate',

    -- Report Generation (All)
    'report.view', 'report.generate', 'report.export', 'report.manage',

    -- Dashboard Access (All)
    'dashboard.analytics', 'dashboard.sales', 'dashboard.inventory', 'dashboard.customer'
);

-- Material Staff role permissions (role_id = 3)
-- Material Staff have access to material and inventory management
SELECT 3, permission_id FROM Permission
WHERE permission_name IN (
    -- Material Management (Cannot delete)
    'material.view',
    'material.create',
    'material.edit',
    'material.import',
    'material.export',
    'material.adjust',

    -- Material Transaction (Cannot manage)
    'material_transaction.view'
);
GO

-- Decanting Staff role permissions (role_id = 4)
-- Decanting Staff have access to product and inventory management
SELECT 4, permission_id FROM Permission
WHERE permission_name IN (
    -- Material Management (Only view)
    'material.view',

    -- Inventory Management (All)
    'inventory.view',
    'inventory.import',
    'inventory.export',
    'inventory.adjust',
    'inventory.sell',
    'inventory.combine',

    -- Product Management (Only view)
    'product.view'
);
GO

-- Order Staff role permissions (role_id = 5)
-- Order Staff have access to order and payment management
SELECT 5, permission_id FROM Permission
WHERE permission_name IN (
    -- Inventory Management (Only view)
    'inventory.view',

    -- Inventory Transaction (Only view)
    'inventory_transaction.view',

    -- Order Management (Cannot delete)
    'order.view',
    'order.create',
    'order.edit',
    'order.process',

    -- Payment Management (Cannot view and process)
    'payment.view',
    'payment.process',

    -- Shipment Management (Cannot delete)
    'shipment.view',
    'shipment.create',
    'shipment.edit',
    'shipment.track',

    -- Cart Management (Only view)
    'cart.view',

    -- Customer Management (Can view and rating)
    'customer.view',
    'customer.rating',

    -- Conversation Management (Only view)
    'conversation.view',
    'conversation.create',
    'conversation.respond',
    'conversation.close',
    'conversation.rate'
);
GO

-- Customer Care role permissions (role_id = 6)
-- Customer Care have access to customer and conversation management
SELECT 6, permission_id FROM Permission
WHERE permission_name IN (
    -- Customer Management (Can delete and view sensitive)
    'customer.view',
    'customer.create',
    'customer.edit',
    'customer.rating',

    -- Cart Management (Only view)
    'cart.view',

    -- Order Management (Only view)
    'order.view',

    -- Payment Management (Only view)
    'payment.view',

    -- Shipment Management (Only view)
    'shipment.view',

    -- Conversation Management (Cannot delete)
    'conversation.view',
    'conversation.create',
    'conversation.respond',
    'conversation.close',
    'conversation.rate'
);
GO

-- Data Analyst role permissions (role_id = 7)
-- Data Analyst have access to report generation and dashboard
SELECT 7, permission_id FROM Permission
WHERE permission_name IN (
    -- Report Generation (All)
    'report.view',
    'report.generate',
    'report.export',
    'report.manage',

    -- Dashboard Access (All)
    'dashboard.analytics',
    'dashboard.sales',
    'dashboard.inventory',
    'dashboard.customer'
);

-- Staff (default role) permissions (role_id = 8)
-- Staff have limited access to view only
SELECT 8, permission_id FROM Permission
WHERE permission_name IN (
    -- Material Management (Only view)
    'material.view',

    -- Inventory Management (Only view)
    'inventory.view',

    -- Product Management (Only view)
    'product.view'
);
GO


