(8, 'Chopard Happy Spirit Set ', 'Unknown', 100, 2007900.0, 2007900.0, 0, 0, 'https://assets.goldenscent.com/catalog/product/cache/1/small_image/750x750/9df78eab33525d08d6e5fb8d27136e95/3/6/3614222719205_chopard_happy_spirit_edp_75_ml_body_lotion_2_50_ml.jpg'),
